import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

interface DayForecast {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  location?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: 'C' | 'F';
  forecast?: DayForecast[];
  onLocationClick?: () => void;
}

// Helper function to get emoji for weather condition
const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rain') || conditionLower.includes('shower')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  return '🌤️'; // Default
};

export default function GeneratedComponent({
  location = 'San Francisco, CA',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', condition: 'Sunny', high: 75, low: 62 },
    { day: 'Tue', condition: 'Cloudy', high: 70, low: 58 },
    { day: 'Wed', condition: 'Rainy', high: 65, low: 55 },
    { day: 'Thu', condition: 'Sunny', high: 74, low: 61 },
    { day: 'Fri', condition: 'Partly Cloudy', high: 72, low: 60 },
  ],
  onLocationClick,
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);
  const speedUnit = unit === 'C' ? 'km/h' : 'mph';

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-4, 16px)">
      <Card
        padding="var(--ggui-spacing-6, 24px)"
        shadow="md"
        style={{
          background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
          borderTop: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
        }}
      >
        <Stack direction="vertical" gap={24}>
          {/* Header with Location */}
          <Stack direction="vertical" gap={8}>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="bold"
              onClick={onLocationClick}
              style={{
                cursor: onLocationClick ? 'pointer' : 'default',
                textDecoration: onLocationClick ? 'underline' : 'none',
              }}
            >
              {location}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="medium"
            >
              {new Date().toLocaleDateString('en-US', {
                weekday: 'long',
                month: 'long',
                day: 'numeric',
              })}
            </Text>
          </Stack>

          <Divider margin={8} />

          {/* Current Weather Section */}
          <Stack direction="vertical" gap={16} align="center">
            {/* Large Temperature */}
            <div
              style={{
                display: 'flex',
                alignItems: 'flex-start',
                gap: '12px',
              }}
            >
              <Text
                variant="h1"
                color="var(--ggui-color-primary-800, #075985)"
                weight="bold"
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  lineHeight: '1',
                }}
              >
                {temperature}°
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-primary-700, #0369a1)"
                weight="medium"
                style={{ marginTop: '8px' }}
              >
                {unit}
              </Text>
            </div>

            {/* Weather Condition with Emoji */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <span style={{ fontSize: '48px' }}>{weatherEmoji}</span>
              <Text
                variant="h2"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="semibold"
              >
                {condition}
              </Text>
            </div>
          </Stack>

          {/* Details Row: Humidity & Wind */}
          <Row gap={16} justify="center" align="stretch">
            {/* Humidity Card */}
            <div
              style={{
                flex: 1,
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'rgba(255, 255, 255, 0.7)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="semibold"
                style={{ textTransform: 'uppercase', letterSpacing: '0.05em' }}
              >
                Humidity
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="bold"
                style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}
              >
                {humidity}%
              </Text>
            </div>

            {/* Wind Speed Card */}
            <div
              style={{
                flex: 1,
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'rgba(255, 255, 255, 0.7)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="semibold"
                style={{ textTransform: 'uppercase', letterSpacing: '0.05em' }}
              >
                Wind
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="bold"
                style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}
              >
                {windSpeed} {speedUnit}
              </Text>
            </div>
          </Row>

          <Divider margin={8} />

          {/* 5-Day Forecast */}
          <Stack direction="vertical" gap={12}>
            <Text
              variant="label"
              color="var(--ggui-color-primary-800, #075985)"
              weight="semibold"
              style={{ textTransform: 'uppercase', letterSpacing: '0.05em' }}
            >
              5-Day Forecast
            </Text>

            <Row gap={8} justify="between" align="stretch" wrap={true}>
              {forecast.map((day, index) => (
                <div
                  key={index}
                  style={{
                    flex: 1,
                    minWidth: 'min(60px, 100%)',
                    padding: 'var(--ggui-spacing-3, 12px)',
                    backgroundColor: 'rgba(255, 255, 255, 0.8)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                    textAlign: 'center',
                    transition: 'all 200ms ease-out',
                  }}
                  onMouseEnter={(e) => {
                    (e.currentTarget as HTMLDivElement).style.backgroundColor =
                      'rgba(255, 255, 255, 1)';
                    (e.currentTarget as HTMLDivElement).style.boxShadow =
                      'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                  }}
                  onMouseLeave={(e) => {
                    (e.currentTarget as HTMLDivElement).style.backgroundColor =
                      'rgba(255, 255, 255, 0.8)';
                    (e.currentTarget as HTMLDivElement).style.boxShadow = 'none';
                  }}
                >
                  <Text
                    variant="label"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    weight="semibold"
                  >
                    {day.day}
                  </Text>

                  <div
                    style={{
                      fontSize: '24px',
                      margin: 'var(--ggui-spacing-2, 8px) 0',
                    }}
                  >
                    {getWeatherEmoji(day.condition)}
                  </div>

                  <Stack direction="vertical" gap={4}>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-primary-900, #0c4a6e)"
                      weight="semibold"
                    >
                      {day.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-primary-500, #0ea5e9)"
                      weight="normal"
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </div>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button,
  Divider,
  Icon,
  Badge,
} from '@ggui-ai/design/primitives';

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: string;
  features: string[];
  comments: string;
}

interface Props {
  satisfactionLabels?: { value: string; label: string; description?: string }[];
  featureOptions?: { value: string; label: string }[];
  onSubmit?: (answers: SurveyAnswers) => void;
}

export default function GeneratedComponent({
  satisfactionLabels = [
    { value: '1', label: 'Very Unsatisfied' },
    { value: '2', label: 'Unsatisfied' },
    { value: '3', label: 'Neutral' },
    { value: '4', label: 'Satisfied' },
    { value: '5', label: 'Very Satisfied' },
  ],
  featureOptions = [
    { value: 'ease-of-use', label: 'Ease of Use' },
    { value: 'performance', label: 'Performance & Speed' },
    { value: 'features', label: 'Feature Set' },
    { value: 'support', label: 'Customer Support' },
    { value: 'pricing', label: 'Pricing & Value' },
    { value: 'design', label: 'Design & UX' },
  ],
  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState(0);
  const totalSteps = 5;
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const validateEmail = (val: string): string => {
    if (!val) return 'Email is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val)) return 'Invalid email format';
    return '';
  };

  const validateName = (val: string): string => {
    if (!val) return 'Name is required';
    return val.trim().length < 2 ? 'Name must be at least 2 characters' : '';
  };

  const nameError = touched.name ? validateName(name) : '';
  const emailError = touched.email ? validateEmail(email) : '';
  const isStep1Valid = useMemo(() => !validateName(name) && !validateEmail(email), [name, email]);
  const isStep2Valid = satisfactionRating !== '';
  const maxChars = 500;
  const charPercent = (comments.length / maxChars) * 100;

  const goToNext = () => {
    if (currentStep === 0) {
      setTouched({ name: true, email: true });
      if (!isStep1Valid) return;
    }
    if (currentStep === 1 && !isStep2Valid) return;
    setCurrentStep((p) => Math.min(p + 1, totalSteps - 1));
  };

  const progressPercent = ((currentStep + 1) / totalSteps) * 100;
  const stepNames = ['Contact', 'Rating', 'Features', 'Comments', 'Review'];

  return (
    <Container maxWidth="md">
      <Card padding={24} shadow="md" style={{ borderTop: '3px solid var(--ggui-color-primary-600, #0284c7)' }}>
        <Stack direction="vertical" gap={20} role="form" aria-label="Customer feedback survey">
          <div>
            <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)" style={{ marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
              Customer Feedback Survey
            </Text>
            <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
              Help us improve by sharing your experience
            </Text>
          </div>

          <div style={{ width: '100%', marginBottom: 'var(--ggui-spacing-6, 24px)' }}>
            <Row justify="between" align="center" gap={8}>
              <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                Step {currentStep + 1} of {totalSteps}
              </Text>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                {stepNames[currentStep]}
              </Text>
            </Row>
            <div style={{
              width: '100%',
              height: '8px',
              backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              overflow: 'hidden',
              marginTop: 'var(--ggui-spacing-2, 8px)',
            }}>
              <div style={{
                width: progressPercent + '%',
                height: '100%',
                backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
                transition: 'width 200ms ease-out',
              }} />
            </div>
          </div>

          <Divider />

          <div style={{ minHeight: '300px' }}>
            {currentStep === 0 && (
              <Stack direction="vertical" gap={16}>
                <div>
                  <Text as="label" htmlFor="name" variant="label" weight="semibold">Full Name</Text>
                  <Input id="name" placeholder="Enter your full name" value={name} onChange={setName}
                    onBlur={() => setTouched((p) => ({ ...p, name: true }))} error={nameError} required />
                </div>
                <div>
                  <Text as="label" htmlFor="email" variant="label" weight="semibold">Email Address</Text>
                  <Input id="email" type="email" placeholder="you@example.com" value={email} onChange={setEmail}
                    onBlur={() => setTouched((p) => ({ ...p, email: true }))} error={emailError} required />
                </div>
                <div style={{
                  padding: 'var(--ggui-spacing-4, 16px)',
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  borderLeft: '4px solid var(--ggui-color-primary-600, #0284c7)',
                }}>
                  <Text variant="caption" color="var(--ggui-color-primary-900, #0c4a6e)">
                    Both fields are required and will be used to send you the survey results.
                  </Text>
                </div>
              </Stack>
            )}

            {currentStep === 1 && (
              <Stack direction="vertical" gap={16}>
                <Text variant="label" weight="semibold" style={{ marginBottom: 'var(--ggui-spacing-4, 16px)' }}>
                  How satisfied are you with our product?
                </Text>
                <RadioGroup value={satisfactionRating} onChange={setSatisfactionRating} options={satisfactionLabels} direction="vertical" />
                {satisfactionRating && (
                  <div style={{
                    padding: 'var(--ggui-spacing-4, 16px)',
                    backgroundColor: 'var(--ggui-color-success-50, #f0fdf4)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    borderLeft: '4px solid var(--ggui-color-success-500, #22c55e)',
                  }}>
                    <Text variant="caption" color="var(--ggui-color-success-900, #14532d)">
                      You selected: {satisfactionLabels.find((o) => o.value === satisfactionRating)?.label}
                    </Text>
                  </div>
                )}
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack direction="vertical" gap={16}>
                <div>
                  <Text variant="label" weight="semibold" style={{ marginBottom: 'var(--ggui-spacing-4, 16px)' }}>
                    Which features interest you most?
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{ marginBottom: 'var(--ggui-spacing-4, 16px)' }}>
                    Select all that apply
                  </Text>
                </div>
                <Stack direction="vertical" gap={12}>
                  {featureOptions.map((f) => (
                    <Checkbox key={f.value} label={f.label} checked={selectedFeatures.includes(f.value)}
                      onChange={() => setSelectedFeatures((p) => p.includes(f.value) ? p.filter((x) => x !== f.value) : [...p, f.value])} />
                  ))}
                </Stack>
                {selectedFeatures.length > 0 && (
                  <div style={{
                    padding: 'var(--ggui-spacing-4, 16px)',
                    backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  }}>
                    <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-900, #0c4a6e)" style={{ marginBottom: 'var(--ggui-spacing-2, 8px)', display: 'block' }}>
                      Selected ({selectedFeatures.length}):
                    </Text>
                    <Row gap={6} wrap style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
                      {selectedFeatures.map((v) => (
                        <Badge key={v} variant="primary" size="sm">
                          {featureOptions.find((f) => f.value === v)?.label}
                        </Badge>
                      ))}
                    </Row>
                  </div>
                )}
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack direction="vertical" gap={16}>
                <div>
                  <Row justify="between" align="center">
                    <Text as="label" htmlFor="comments" variant="label" weight="semibold">Additional Comments</Text>
                    <Text variant="caption" color={charPercent > 80 ? 'var(--ggui-color-warning-600, #d97706)' : 'var(--ggui-color-neutral-500, #6b7280)'}>
                      {comments.length}/{maxChars}
                    </Text>
                  </Row>
                  <TextArea id="comments" placeholder="Tell us more about your experience... (optional)" value={comments}
                    onChange={(v) => setComments(v.slice(0, maxChars))} rows={5} maxLength={maxChars} />
                </div>
                <div style={{
                  width: '100%',
                  height: '6px',
                  backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  overflow: 'hidden',
                }}>
                  <div style={{
                    width: charPercent + '%',
                    height: '100%',
                    backgroundColor: charPercent > 90 ? 'var(--ggui-color-error-500, #ef4444)' : charPercent > 80 ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-primary-600, #0284c7)',
                    transition: 'width 100ms ease-out',
                  }} />
                </div>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  Optional. You have {maxChars - comments.length} characters remaining.
                </Text>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack direction="vertical" gap={16}>
                <div style={{
                  padding: 'var(--ggui-spacing-4, 16px)',
                  backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  borderLeft: '4px solid var(--ggui-color-primary-600, #0284c7)',
                }}>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-primary-900, #0c4a6e)">
                    Please review your answers before submitting
                  </Text>
                </div>
                <Card padding={16}>
                  <Stack direction="vertical" gap={12}>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">Contact Information</Text>
                    <Divider />
                    <Row justify="between"><Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Name</Text><Text variant="body" weight="semibold">{name}</Text></Row>
                    <Row justify="between"><Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Email</Text><Text variant="body" weight="semibold">{email}</Text></Row>
                  </Stack>
                </Card>
                <Card padding={16}>
                  <Stack direction="vertical" gap={12}>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">Satisfaction Rating</Text>
                    <Divider />
                    <Row justify="between" align="center">
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Rating</Text>
                      <Badge variant="primary">{satisfactionLabels.find((o) => o.value === satisfactionRating)?.label} ({satisfactionRating}/5)</Badge>
                    </Row>
                  </Stack>
                </Card>
                <Card padding={16}>
                  <Stack direction="vertical" gap={12}>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">Feature Interests</Text>
                    <Divider />
                    {selectedFeatures.length > 0 ? (
                      <Row gap={6} wrap>
                        {selectedFeatures.map((v) => (
                          <Badge key={v} variant="info" size="sm">{featureOptions.find((f) => f.value === v)?.label}</Badge>
                        ))}
                      </Row>
                    ) : (
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">No features selected</Text>
                    )}
                  </Stack>
                </Card>
                <Card padding={16}>
                  <Stack direction="vertical" gap={12}>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">Comments</Text>
                    <Divider />
                    {comments ? (
                      <Text variant="body" style={{ fontStyle: 'italic', color: 'var(--ggui-color-neutral-700, #374151)', whiteSpace: 'pre-wrap' }}>
                        "{comments}"
                      </Text>
                    ) : (
                      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">No comments provided</Text>
                    )}
                  </Stack>
                </Card>
                <div style={{
                  padding: 'var(--ggui-spacing-4, 16px)',
                  backgroundColor: 'var(--ggui-color-success-50, #f0fdf4)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  borderLeft: '4px solid var(--ggui-color-success-500, #22c55e)',
                }}>
                  <Text variant="caption" color="var(--ggui-color-success-900, #14532d)">
                    All required fields are complete. Click submit to send your survey response.
                  </Text>
                </div>
              </Stack>
            )}
          </div>

          <Divider />

          <Row justify="between" align="center">
            {currentStep > 0 ? (
              <Button variant="outline" onClick={() => setCurrentStep((p) => Math.max(p - 1, 0))} leftIcon={<Icon name="chevron-left" size={16} />}>
                Back
              </Button>
            ) : (
              <div />
            )}
            {currentStep < totalSteps - 1 ? (
              <Button variant="primary" onClick={goToNext} disabled={(currentStep === 0 && !isStep1Valid) || (currentStep === 1 && !isStep2Valid)}
                rightIcon={<Icon name="chevron-right" size={16} />}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => {
                if (onSubmit) onSubmit({ name, email, satisfactionRating, features: selectedFeatures, comments });
              }} rightIcon={<Icon name="check" size={16} />}>
                Submit Survey
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Icon,
  Divider,
} from '@ggui-ai/design/primitives';

export type ColumnId = 'todo' | 'in-progress' | 'done';
export type PriorityLevel = 'low' | 'medium' | 'high';

export interface Task {
  id: string;
  title: string;
  priority: PriorityLevel;
  assignee?: { name: string; initials: string; color?: string };
  dueDate?: string;
  columnId: ColumnId;
}

interface Props {
  tasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
}

const COLUMNS: ColumnId[] = ['todo', 'in-progress', 'done'];
const COLUMN_NAMES: Record<ColumnId, string> = { 'todo': 'To Do', 'in-progress': 'In Progress', 'done': 'Done' };
const PRIORITY_COLORS: Record<PriorityLevel, string> = { 'low': 'success', 'medium': 'warning', 'high': 'error' };
const PRIORITY_LABELS: Record<PriorityLevel, string> = { 'low': 'Low', 'medium': 'Medium', 'high': 'High' };

const DEFAULT_TASKS: Task[] = [
  { id: '1', title: 'Design login page', priority: 'high', assignee: { name: 'Alice Johnson', initials: 'AJ', color: 'var(--ggui-color-primary-600, #0284c7)' }, dueDate: '2024-02-15', columnId: 'todo' },
