function getPriorityColor(priority: PriorityLevel): 'success' | 'warning' | 'error' {
  return priority === 'low' ? 'success' : priority === 'high' ? 'error' : 'warning';
}

function getBorderStyle(priority: PriorityLevel): React.CSSProperties {
  if (priority === 'low') return { borderLeft: '4px solid var(--ggui-color-success-500, #22c55e)' };
  if (priority === 'high') return { borderLeft: '4px solid var(--ggui-color-error-500, #ef4444)' };
  return { borderLeft: '4px solid var(--ggui-color-warning-500, #f59e0b)' };
}

function generateId(): string {
  return Math.random().toString(36).substring(2, 11);
}

function AvatarInitials({ initials, color }: { initials: string; color?: string }) {
  const bgColor = color || 'var(--ggui-color-neutral-300, #d1d5db)';
  return (
    <div
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        width: '32px',
        height: '32px',
        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
        backgroundColor: bgColor,
        color: '#ffffff',
        fontSize: 'var(--ggui-font-size-sm, 14px)',
        fontWeight: 'var(--ggui-font-weight-semibold, 600)',
      }}
      title={initials}
    >
      {initials}
    </div>
  );
}

function TaskCard({
  task,
  onEdit,
  onMove,
  onDelete,
}: {
  task: Task;
  onEdit: (task: Task) => void;
  onMove: (taskId: string, columnId: ColumnId) => void;
  onDelete: (taskId: string) => void;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title);

  const handleSaveTitle = () => {
    if (editTitle.trim()) {
      onEdit({ ...task, title: editTitle.trim() });
      setIsEditing(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') handleSaveTitle();
    else if (e.key === 'Escape') {
      setIsEditing(false);
      setEditTitle(task.title);
    }
  };

  return (
    <Card padding={12} shadow="sm" style={getBorderStyle(task.priority)}>
      <Stack direction="vertical" gap={8}>
        <div onClick={() => setIsEditing(true)} style={{ cursor: 'pointer' }}>
          {isEditing ? (
            <input
              type="text"
              value={editTitle}
              onChange={(e) => setEditTitle(e.currentTarget.value)}
              onBlur={handleSaveTitle}
              onKeyDown={handleKeyDown}
              autoFocus
              style={{
                width: '100%',
                padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                fontSize: 'var(--ggui-font-size-sm, 14px)',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                border: '1px solid var(--ggui-color-primary-300, #7dd3fc)',
                fontWeight: 'var(--ggui-font-weight-medium, 500)',
              }}
            />
          ) : (
            <Text weight="semibold" style={{ lineHeight: '1.4' }}>
              {task.title}
            </Text>
          )}
        </div>
        <Badge variant={getPriorityColor(task.priority)} size="sm">
          {PRIORITY_LABELS[task.priority]}
        </Badge>
        <Row gap={8} align="center">
          {task.assignee && <AvatarInitials initials={task.assignee.initials} color={task.assignee.color} />}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              {new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </Text>
          )}
        </Row>
        <Divider margin={4} />
        <Row gap={4} justify="between">
          <Select
            value={task.columnId}
            onChange={(col) => onMove(task.id, col as ColumnId)}
            options={COLUMNS.map((c) => ({ value: c, label: COLUMN_NAMES[c] }))}
          />
          <Button
            variant="ghost"
            size="sm"
            onClick={() => onDelete(task.id)}
            rightIcon={<Icon name="x" size={16} />}
            aria-label="Delete task"
          />
        </Row>
      </Stack>
    </Card>
  );
}

function AddTaskForm({
  onAdd,
  onCancel,
}: {
  onAdd: (title: string, priority: PriorityLevel) => void;
  onCancel: () => void;
}) {
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState<PriorityLevel>('medium');

  return (
    <Stack direction="vertical" gap={8}>
      <Input label="Task Title" placeholder="Enter task title..." value={title} onChange={setTitle} />
      <Select
        label="Priority"
        value={priority}
        onChange={(p) => setPriority(p as PriorityLevel)}
        options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]}
      />
      <Row gap={8}>
        <Button
          variant="primary"
          size="sm"
          onClick={() => {
            if (title.trim()) {
              onAdd(title.trim(), priority);
              setTitle('');
              setPriority('medium');
            }
          }}
          disabled={!title.trim()}
          leftIcon={<Icon name="plus" size={16} />}
          fullWidth
        >
          Add Task
        </Button>
        <Button variant="outline" size="sm" onClick={onCancel}>
          Cancel
        </Button>
      </Row>
    </Stack>
  );
}

function Column({
  columnId,
  tasks,
  onTaskEdit,
  onTaskMove,
  onTaskDelete,
  onAddTask,
}: {
  columnId: ColumnId;
  tasks: Task[];
  onTaskEdit: (task: Task) => void;
  onTaskMove: (taskId: string, columnId: ColumnId) => void;
  onTaskDelete: (taskId: string) => void;
  onAddTask: (title: string, priority: PriorityLevel) => void;
}) {
  const [showForm, setShowForm] = useState(false);
  const isCompleted = columnId === 'done';
  const bgColor = isCompleted ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-neutral-50, #f9fafb)';
  const variant = isCompleted ? 'success' : 'primary';

  return (
    <div
      style={{
        flex: 1,
        minWidth: '280px',
        display: 'flex',
        flexDirection: 'column',
        backgroundColor: bgColor,
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        padding: 'var(--ggui-spacing-4, 16px)',
        gap: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Row justify="between" align="center">
        <Text variant="h3" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
          {COLUMN_NAMES[columnId]}
        </Text>
        <Badge variant={variant} size="sm">
          {tasks.length}
        </Badge>
      </Row>
      <Stack direction="vertical" gap={8} style={{ flex: 1 }}>
        {tasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onEdit={onTaskEdit}
            onMove={onTaskMove}
            onDelete={onTaskDelete}
          />
        ))}
      </Stack>
      <Divider margin={4} />
      {showForm ? (
        <AddTaskForm
          onAdd={(title, priority) => {
            onAddTask(title, priority);
            setShowForm(false);
          }}
          onCancel={() => setShowForm(false)}
        />
      ) : (
        <Button
          variant="outline"
          size="sm"
          onClick={() => setShowForm(true)}
          leftIcon={<Icon name="plus" size={16} />}
          fullWidth
        >
          Add Task
        </Button>
      )}
    </div>
  );
}

export default function GeneratedComponent({ tasks: initialTasks = DEFAULT_TASKS, onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);

  const tasksByColumn: Record<ColumnId, Task[]> = {
    'todo': tasks.filter((t) => t.columnId === 'todo'),
    'in-progress': tasks.filter((t) => t.columnId === 'in-progress'),
    'done': tasks.filter((t) => t.columnId === 'done'),
  };

  const totalTasks = tasks.length;
  const completedTasks = tasksByColumn.done.length;
  const completionPct = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

  const updateTasks = (newTasks: Task[]) => {
    setTasks(newTasks);
    onTaskUpdate?.(newTasks);
  };

  const handleTaskEdit = (updated: Task) => {
    updateTasks(tasks.map((t) => (t.id === updated.id ? updated : t)));
  };

  const handleTaskMove = (taskId: string, newCol: ColumnId) => {
    updateTasks(tasks.map((t) => (t.id === taskId ? { ...t, columnId: newCol } : t)));
  };

  const handleTaskDelete = (taskId: string) => {
    updateTasks(tasks.filter((t) => t.id !== taskId));
  };

  const handleAddTask = (title: string, priority: PriorityLevel) => {
    const newId = generateId();
    updateTasks([...tasks, { id: newId, title, priority, columnId: 'todo' }]);
  };

  return (
    <Container maxWidth="full" padding={24} center={false}>
      <Stack direction="vertical" gap={24}>
        <Card
          padding={16}
          shadow="sm"
          style={{
            background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
            borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
          }}
        >
          <Row justify="between" align="center">
            <Stack direction="vertical" gap={4}>
              <Text weight="semibold" color="var(--ggui-color-primary-900, #0c4a6e)">
                Progress
              </Text>
              <Text color="var(--ggui-color-primary-700, #0369a1)">
                {completedTasks} of {totalTasks} tasks completed
              </Text>
            </Stack>
            <div style={{ textAlign: 'center', '--progress-degrees': completionPct * 3.6 } as React.CSSProperties}>
              <div
                style={{
                  width: '80px',
                  height: '80px',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  background: 'conic-gradient(var(--ggui-color-primary-500, #0ea5e9) 0deg, var(--ggui-color-primary-500, #0ea5e9) var(--progress-degrees), var(--ggui-color-primary-200, #bae6fd) var(--progress-degrees), var(--ggui-color-primary-200, #bae6fd) 360deg)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                }}
              >
                <div
                  style={{
                    width: '68px',
                    height: '68px',
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexDirection: 'column',
                  }}
                >
                  <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>
                    {completionPct}%
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                    Done
                  </Text>
                </div>
              </div>
            </div>
          </Row>
        </Card>
        <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4, 16px)', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          {COLUMNS.map((columnId) => (
            <Column
              key={columnId}
              columnId={columnId}
              tasks={tasksByColumn[columnId]}
              onTaskEdit={handleTaskEdit}
              onTaskMove={handleTaskMove}
              onTaskDelete={handleTaskDelete}
              onAddTask={handleAddTask}
            />
          ))}
        </div>
      </Stack>
    </Container>
  );
}

