function ElementCell({
  element,
  onClick,
  isFiltered,
}: {
  element: Element;
  onClick: () => void;
  isFiltered: boolean;
}) {
  const { motionEnabled } = useMotion();
  const colors = categoryColors[element.category] || categoryColors['Nonmetals'];
  const bgColor = colors.bg;
  const borderColor = colors.border;
  const textColor = colors.text;
  const lightColor = colors.lightBg;

  return (
    <button
      onClick={onClick}
      style={{
        backgroundColor: bgColor,
        border: '2px solid ' + borderColor,
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        padding: 'var(--ggui-spacing-2, 8px)',
        cursor: 'pointer',
        color: textColor,
        fontFamily: 'system-ui, -apple-system, sans-serif',
        transition: isFiltered ? 'none' : transition.colors,
        opacity: isFiltered ? 0.3 : 1,
        transform: isFiltered ? 'scale(0.95)' : 'scale(1)',
        animation: motionEnabled && !isFiltered ? animation.scaleIn : 'none',
        minHeight: '80px',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        overflow: 'hidden',
      }}
      onMouseEnter={(e) => {
        if (!isFiltered) {
          e.currentTarget.style.boxShadow = '0 0 0 3px ' + lightColor;
          e.currentTarget.style.transform = 'scale(1.05)';
        }
      }}
      onMouseLeave={(e) => {
        if (!isFiltered) {
          e.currentTarget.style.boxShadow = 'none';
          e.currentTarget.style.transform = 'scale(1)';
        }
      }}
      aria-label={element.name + ' (' + element.symbol + '), atomic number ' + element.atomicNumber}
    >
      <div style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', fontWeight: 'var(--ggui-font-weight-semibold, 600)', position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)', opacity: 0.9 }}>
        {element.atomicNumber}
      </div>
      <div style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', lineHeight: 1 }}>
        {element.symbol}
      </div>
      <div style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', marginTop: 'var(--ggui-spacing-1, 4px)', opacity: 0.9 }}>
        {element.atomicWeight.toFixed(3)}
      </div>
    </button>
  );
}

function PeriodicTableGrid({
  elements,
  searchTerm,
  onElementClick,
}: {
  elements: Element[];
  searchTerm: string;
  onElementClick: (element: Element) => void;
}) {
  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lower = searchTerm.toLowerCase();
    return elements.filter((el) => el.name.toLowerCase().includes(lower) || el.symbol.toLowerCase().includes(lower));
  }, [elements, searchTerm]);

  const gridStyle: React.CSSProperties = {
    display: 'grid',
    gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
    gap: 'var(--ggui-spacing-2, 8px)',
    padding: 'var(--ggui-spacing-4, 16px)',
    backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
  };

  const elementMap = new Map(elements.map((el) => [el.atomicNumber, el]));
  const children: React.ReactNode[] = [];

  for (let i = 1; i <= 118; i++) {
    const el = elementMap.get(i);
    if (el) {
      const isFiltered = !filteredElements.includes(el);
      children.push(
        <div key={i} style={{ gridColumn: el.group, gridRow: el.period }}>
          <ElementCell element={el} onClick={() => onElementClick(el)} isFiltered={isFiltered} />
        </div>
      );
    }
  }

  return <div style={gridStyle}>{children}</div>;
}

function CategoryLegend() {
  const cats = Object.entries(categoryColors);
  const items: React.ReactNode[] = [];

  for (let i = 0; i < cats.length; i++) {
    const [category, colors] = cats[i];
    const bgCol = colors.bg;
    const borderCol = colors.border;
    items.push(
      <Row key={category} gap={8} align="center">
        <div style={{ width: '16px', height: '16px', backgroundColor: bgCol, border: '2px solid ' + borderCol, borderRadius: 'var(--ggui-shape-radius-sm, 4px)', flexShrink: 0 }} />
        <Text variant="label" color="var(--ggui-color-neutral-700, #374151)" style={{ fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
          {category}
        </Text>
      </Row>
    );
  }

  return (
    <Card padding="var(--ggui-spacing-4, 16px)" border>
      <Stack direction="vertical" gap={12}>
        <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)" weight="semibold">
          Element Categories
        </Text>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: 'var(--ggui-spacing-4, 16px)' }}>
          {items}
        </div>
      </Stack>
    </Card>
  );
}

function DetailPanel({
