      <Stack direction="vertical" gap={16}>
        <Row justify="between" align="center">
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-4, 16px)', marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
              <div style={{ width: '60px', height: '60px', backgroundColor: bgCol, border: '3px solid ' + borderCol, borderRadius: 'var(--ggui-shape-radius-md, 8px)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: colors.text, fontSize: 'var(--ggui-font-size-3xl, 30px)', fontWeight: 'var(--ggui-font-weight-bold, 700)' }}>
                {element.symbol}
              </div>
              <div>
                <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)" weight="bold">
                  {element.name}
