            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)" weight="semibold">
              Atomic Weight
            </Text>
            <Text variant="body" weight="bold" color="var(--ggui-color-neutral-900, #111827)">
              {element.atomicWeight.toFixed(3)} u
            </Text>
          </div>
          <div>
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)" weight="semibold">
              Period
            </Text>
            <Text variant="body" weight="bold" color="var(--ggui-color-neutral-900, #111827)">
              {element.period}
            </Text>
          </div>
          <div>
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)" weight="semibold">
              Group
            </Text>
            <Text variant="body" weight="bold" color="var(--ggui-color-neutral-900, #111827)">
              {element.group}
            </Text>
          </div>
        </div>

        <div>
          <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)" weight="semibold">
            Electron Configuration
          </Text>
          <Text variant="body" weight="normal" color="var(--ggui-color-neutral-900, #111827)" style={{ fontFamily: 'monospace', marginTop: 'var(--ggui-spacing-1, 4px)', padding: 'var(--ggui-spacing-2, 8px)', backgroundColor: 'var(--ggui-color-neutral-100, #f3f4f6)', borderRadius: 'var(--ggui-shape-radius-sm, 4px)' }}>
            {element.electronConfiguration}
          </Text>
        </div>
      </Stack>
    </Card>
  );
}

