import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Icon,
  Badge,
  Tabs,
  Table,
  Divider,
} from '@ggui-ai/design/primitives';

interface Review {
  id: string;
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Specification {
  key: string;
  value: string;
}

interface Props {
  productId?: string;
  productName?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  stockStatus?: 'in-stock' | 'low-stock' | 'out-of-stock';
  stock?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

// Helper: Render star rating (filled/empty)
function StarRating({ rating, size = 16 }: { rating: number; size?: number }) {
  const fullStars = Math.floor(rating);
  const hasHalf = rating % 1 >= 0.5;
  const emptyStars = 5 - fullStars - (hasHalf ? 1 : 0);
  const fullStarArray = Array.from({ length: fullStars });
  const emptyStarArray = Array.from({ length: emptyStars });

  return (
    <Row gap={4} align="center">
      {fullStarArray.map((_, index) => (
        <Icon key={'full' + String(index)} name="check" size={size} color="var(--ggui-color-warning-500, #f59e0b)" />
      ))}
      {hasHalf && (
        <div
          style={{
            width: size,
            height: size,
            background: 'linear-gradient(to right, var(--ggui-color-warning-500, #f59e0b) 50%, var(--ggui-color-neutral-300, #d1d5db) 50%)',
            borderRadius: '2px',
          }}
        />
      )}
      {emptyStarArray.map((_, index) => (
        <Icon
          key={'empty' + String(index)}
          name="check"
          size={size}
          color="var(--ggui-color-neutral-300, #d1d5db)"
        />
      ))}
    </Row>
  );
}

export default function GeneratedComponent({
  productId = 'PROD-001',
  productName = 'Premium Wireless Headphones',
  price = 129.99,
  currency = '$',
  rating = 4.5,
  reviewCount = 128,
  stockStatus = 'in-stock',
  stock = 15,
  description = 'Experience premium sound quality with our wireless headphones. Featuring active noise cancellation, 30-hour battery life, and premium comfort padding for all-day wear. Perfect for music lovers and professionals alike.',
  specifications = [
    { key: 'Driver Size', value: '40mm' },
    { key: 'Frequency Response', value: '20Hz - 20kHz' },
    { key: 'Battery Life', value: '30 hours' },
    { key: 'Bluetooth Version', value: '5.0' },
    { key: 'Weight', value: '250g' },
    { key: 'Colors Available', value: 'Black, Silver, Rose Gold' },
  ],
  reviews = [
    {
      id: '1',
      author: 'Sarah M.',
      rating: 5,
      text: 'Outstanding sound quality and very comfortable. Best headphones I\'ve ever owned!',
      date: '2024-01-15',
    },
    {
      id: '2',
      author: 'John D.',
      rating: 4,
      text: 'Great product, minor connectivity issues on first setup but resolved quickly.',
      date: '2024-01-10',
    },
    {
      id: '3',
      author: 'Emma L.',
      rating: 5,
      text: 'The noise cancellation is incredible. Battery lasts way longer than expected.',
      date: '2024-01-05',
    },
  ],
  onAddToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const isOutOfStock = stockStatus === 'out-of-stock';
  const maxQuantity = stock || 1;

  const handleQuantityIncrease = () => {
    if (quantity < maxQuantity) {
      setQuantity(quantity + 1);
    }
  };

  const handleQuantityDecrease = () => {
    if (quantity > 1) {
      setQuantity(quantity - 1);
    }
  };

  const handleAddToCart = () => {
    if (onAddToCart && !isOutOfStock) {
      onAddToCart({ productId, quantity });
    }
  };

  // Format price with currency
  const formattedPrice = currency + price.toFixed(2);

  // Determine stock badge variant
  const getStockBadgeVariant = () => {
    if (stockStatus === 'in-stock') return 'success';
    if (stockStatus === 'low-stock') return 'warning';
    return 'error';
  };

  const getStockBadgeText = () => {
    if (stockStatus === 'in-stock') return 'In Stock';
    if (stockStatus === 'low-stock') return 'Low Stock';
    return 'Out of Stock';
  };

  // Table columns for specifications
  const specColumns = [
    { key: 'key', header: 'Specification', width: '40%' },
    { key: 'value', header: 'Details', width: '60%' },
  ];

  // Tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Stack direction="vertical" gap={12}>
          <Text variant="body" color="var(--ggui-color-neutral-700, #374151)">
            {description}
          </Text>
        </Stack>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Table
          columns={specColumns}
          data={specifications}
          striped
          hoverable
          compact
          caption="Product specifications and technical details"
        />
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews (' + String(reviewCount) + ')',
      content: (
        <Stack direction="vertical" gap={16}>
          {reviews && reviews.length > 0 ? (
            reviews.map((review) => (
              <Card key={review.id} padding={12} border={true} shadow="sm">
                <Stack direction="vertical" gap={8}>
                  <Row justify="between" align="center">
                    <Text variant="label" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                      {review.author}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      {new Date(review.date).toLocaleDateString()}
                    </Text>
                  </Row>
                  <StarRating rating={review.rating} size={14} />
                  <Text variant="body" color="var(--ggui-color-neutral-700, #374151)">
                    {review.text}
                  </Text>
                </Stack>
              </Card>
            ))
          ) : (
            <Text color="var(--ggui-color-neutral-500, #6b7280)">No reviews yet.</Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)">
      <Stack direction="vertical" gap="var(--ggui-spacing-8, 32px)">
        {/* TOP SECTION: Image & Product Info */}
        <Card shadow="md" padding="var(--ggui-spacing-6, 24px)">
          <Row
            direction="horizontal"
            gap="var(--ggui-spacing-6, 24px)"
            align="start"
            wrap={true}
          >
            {/* Product Image Placeholder */}
            <div
              style={{
                flex: '1 1 300px',
                minWidth: '280px',
                height: '400px',
                backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
              }}
            >
              <Stack direction="vertical" gap={8} align="center">
                <div
                  style={{
                    fontSize: '48px',
                    opacity: 0.5,
                  }}
                >
                  📦
                </div>
                <Text
                  variant="label"
                  color="var(--ggui-color-primary-600, #0284c7)"
                  align="center"
                  weight="semibold"
                >
                  {productName}
                </Text>
              </Stack>
            </div>

            {/* Product Details */}
            <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)" style={{ flex: '1 1 300px', minWidth: '280px' }}>
              {/* Title */}
              <Text variant="h2" color="var(--ggui-color-neutral-900, #111827)" weight="bold">
                {productName}
              </Text>

              {/* Price */}
              <Text
                variant="h3"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="bold"
              >
                {formattedPrice}
              </Text>

              {/* Rating */}
              <Row gap={8} align="center">
                <StarRating rating={rating} size={18} />
                <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                  {rating.toFixed(1)}
                </Text>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                  ({'(' + String(reviewCount) + ' reviews)'})
                </Text>
              </Row>

              <Divider margin={8} />

              {/* Stock Status Badge */}
              <Badge variant={getStockBadgeVariant()} size="md">
                {getStockBadgeText()}
              </Badge>

              {/* Stock Info */}
              {!isOutOfStock && (
                <Text variant="caption" color="var(--ggui-color-neutral-600, #4b5563)">
                  {stock} {stock === 1 ? 'item' : 'items'} available
                </Text>
              )}

              <Divider margin={8} />

              {/* Quantity Selector */}
              <Stack direction="vertical" gap={8}>
                <Text variant="label" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                  Quantity
                </Text>
                <Row gap={8} align="center">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleQuantityDecrease}
                    disabled={quantity <= 1 || isOutOfStock}
                    aria-label="Decrease quantity"
                  >
                    <Icon name="minus" size={16} />
                  </Button>
                  <div
                    style={{
                      minWidth: '40px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontWeight: '600',
                      color: 'var(--ggui-color-neutral-900, #111827)',
                    }}
                  >
                    {quantity}
                  </div>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleQuantityIncrease}
                    disabled={quantity >= maxQuantity || isOutOfStock}
                    aria-label="Increase quantity"
                  >
                    <Icon name="plus" size={16} />
                  </Button>
                </Row>
              </Stack>

              <Divider margin={8} />

              {/* Add to Cart Button */}
              <Button
                variant="primary"
                size="lg"
                onClick={handleAddToCart}
                disabled={isOutOfStock}
                fullWidth
                aria-label={isOutOfStock ? 'Product out of stock' : 'Add to cart'}
              >
                {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
              </Button>
            </Stack>
          </Row>
        </Card>

        {/* MIDDLE SECTION: Tabs */}
        <Card shadow="sm" padding="var(--ggui-spacing-6, 24px)">
          <Tabs
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            size="md"
          />
        </Card>
      </Stack>
    </Container>
  );
}

