import { useState, useEffect, useRef } from 'react';
import { Container, Card, Stack, Row, Text, Input, Button, Icon, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  id: string;
  sender: string;
  senderId: string;
  text: string;
  timestamp: string;
}

interface User {
  id: string;
  name: string;
}

interface Props {
  title?: string;
  user?: User;
  initialMessages?: Message[];
  participantCount?: number;
  onSend?: (data: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Conversation',
  user = { id: 'user-1', name: 'You' },
  initialMessages = [],
  participantCount = 2,
  onSend,
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [messageCounter, setMessageCounter] = useState(0);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const handlerRef = useRef<((e: Event) => void) | null>(null);
  const { motionEnabled } = useMotion();

  // Auto-scroll to bottom
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, typingUsers]);

  // Listen for real-time data
  useEffect(() => {
    const handleAgentData = (e: Event) => {
      const customEvent = e as CustomEvent;
      const { type, sender, text, timestamp, senderId } = customEvent.detail;

      if (type === 'message' && sender && text && timestamp) {
        setMessageCounter((prev) => {
          const newCounter = prev + 1;
          const msgId = 'msg-' + newCounter;
          const newMessage: Message = {
            id: msgId,
            sender,
            senderId: senderId || sender,
            text,
            timestamp,
          };
          setMessages((prevMessages) => [...prevMessages, newMessage]);
          return newCounter;
        });

        // Remove typing indicator for this user
        setTypingUsers((prev) => {
          const updated = new Set(prev);
          updated.delete(sender);
          return updated;
        });
      } else if (type === 'typing' && sender) {
        setTypingUsers((prev) => new Set(prev).add(sender));
      }
    };

    handlerRef.current = handleAgentData;
    const eventTarget = typeof window !== 'undefined' ? window : null;

    if (eventTarget) {
      eventTarget.addEventListener('ggui:agent-data', handleAgentData);
      return () => eventTarget.removeEventListener('ggui:agent-data', handleAgentData);
    }
  }, []);

  const handleSend = () => {
    if (!inputValue.trim()) return;

    const timestamp = new Date().toISOString();
    setMessageCounter((prev) => {
      const newCounter = prev + 1;
      const msgId = 'msg-' + newCounter;
      const newMessage: Message = {
        id: msgId,
        sender: user.name,
        senderId: user.id,
        text: inputValue,
        timestamp,
      };
      setMessages((prevMessages) => [...prevMessages, newMessage]);
      return newCounter;
    });

    onSend?.({ text: inputValue, timestamp });
    setInputValue('');
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (isoString: string) => {
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
    } catch {
      return '';
    }
  };

  const isUserMessage = (senderId: string) => senderId === user.id;

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="lg" padding="0">
        <Card shadow="md" padding="0" border={true} style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden' }}>
          {/* Header */}
          <div
            style={{
              background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
              borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              padding: 'var(--ggui-spacing-4, 16px)',
              flexShrink: 0,
            }}
          >
            <Stack direction="horizontal" justify="between" align="center">
              <Stack direction="vertical" gap={4}>
                <Text variant="h3" color="var(--ggui-color-primary-900, #0c4a6e)" weight="semibold">
                  {title}
                </Text>
                <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">
                  {participantCount} participant{participantCount !== 1 ? 's' : ''}
                </Text>
              </Stack>
              <Icon name="settings" size={20} color="var(--ggui-color-primary-600, #0284c7)" />
            </Stack>
          </div>

          {/* Messages List */}
          <div
            style={{
              flex: 1,
              overflowY: 'auto',
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-neutral-50, #f9fafb)',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            {messages.length === 0 && (
              <div
                style={{
                  flex: 1,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  textAlign: 'center',
                }}
              >
                <Stack direction="vertical" gap={8} align="center">
                  <Icon name="user" size={32} color="var(--ggui-color-neutral-300, #d1d5db)" />
                  <Text color="var(--ggui-color-neutral-500, #6b7280)" variant="body">
                    No messages yet. Start a conversation!
                  </Text>
                </Stack>
              </div>
            )}

            {messages.map((msg, index) => {
              const isMine = isUserMessage(msg.senderId);
              return (
                <div
                  key={msg.id}
                  style={{
                    display: 'flex',
                    justifyContent: isMine ? 'flex-end' : 'flex-start',
                    animation: motionEnabled ? animation.slideInUp : 'none',
                    animationDelay: motionEnabled ? (index * 30) + 'ms' : '0ms',
                  }}
                >
                  <div
                    style={{
                      maxWidth: '60%',
                      background: isMine
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-neutral-200, #e5e7eb)',
                      color: isMine ? '#ffffff' : 'var(--ggui-color-neutral-900, #111827)',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                    }}
                  >
                    {!isMine && (
                      <Text
                        variant="label"
                        color={isMine ? '#ffffff' : 'var(--ggui-color-neutral-700, #374151)'}
                        weight="semibold"
                        style={{ display: 'block', marginBottom: '4px' }}
                      >
                        {msg.sender}
                      </Text>
                    )}
                    <Text
                      variant="body"
                      color={isMine ? '#ffffff' : 'var(--ggui-color-neutral-900, #111827)'}
                      style={{ wordBreak: 'break-word' }}
                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
                      color={isMine ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-neutral-500, #6b7280)'}
                      style={{ display: 'block', marginTop: '4px', fontSize: '0.75em' }}
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </div>
                </div>
              );
            })}

            {/* Typing Indicator */}
            {typingUsers.size > 0 && (
              <div
                style={{
                  display: 'flex',
                  justifyContent: 'flex-start',
                  animation: motionEnabled ? animation.fadeIn : 'none',
                }}
              >
                <div
                  style={{
                    background: 'var(--ggui-color-neutral-300, #d1d5db)',
                    padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    display: 'flex',
                    gap: '4px',
                    alignItems: 'center',
                  }}
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-700, #374151)"
                    weight="medium"
                    style={{ marginRight: '4px' }}
                  >
                    {Array.from(typingUsers).join(', ')} typing
                  </Text>
                  <div
                    style={{
                      display: 'flex',
                      gap: '3px',
                    }}
                  >
                    {[0, 1, 2].map((i) => (
                      <div
                        key={'pulse-' + i}
                        style={{
                          width: '6px',
                          height: '6px',
                          borderRadius: '50%',
                          background: 'var(--ggui-color-neutral-600, #4b5563)',
                          animation: 'ggui-pulse 1.4s infinite',
