              </Row>
            </Stack>
          </div>
        </Card>
      </Container>

      <style>{`
        @keyframes ggui-pulse {
          0%, 100% { opacity: 0.6; }
          50% { opacity: 1; }
        }
      `}</style>
    </>
  );
}

