};

function ReviewRow({ label, value }: { label: string; value: string }) {
  return (
    <div style={{ display: 'flex', gap: 'var(--ggui-spacing-4,16px)', padding: 'var(--ggui-spacing-2,8px) 0', borderBottom: '1px solid var(--ggui-color-neutral-200,#e5e7eb)' }}>
      <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700,#0369a1)" style={{ minWidth: 148, flexShrink: 0 } as React.CSSProperties}>{label}</Text>
      <Text color="var(--ggui-color-neutral-700,#374151)" style={{ wordBreak: 'break-word' } as React.CSSProperties}>{value || '—'}</Text>
    </div>
  );
}

export default function GeneratedComponent({
  ratingOptions = DEFAULT_RATINGS,
  featureOptions = DEFAULT_FEATURES,
  title = 'Customer Satisfaction Survey',
  subtitle = 'Help us improve by sharing your experience.',
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();
  const anim = motionEnabled ? { animation: animation.slideInUp } : {};

  const [step, setStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false });
  const [rating, setRating] = useState('');
  const [features, setFeatures] = useState<Set<string>>(new Set());
  const [comments, setComments] = useState('');

  const step1Valid = !validateName(name) && !validateEmail(email);
  const canNext = step === 0 ? step1Valid : step === 1 ? !!rating : true;

  const handleNext = () => {
    if (step === 0) {
      setTouched({ name: true, email: true });
      const ne = validateName(name); const ee = validateEmail(email);
      setNameError(ne); setEmailError(ee);
      if (ne || ee) return;
    }
    setStep(s => s + 1);
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    const answers: SurveyAnswers = {
      name: name.trim(), email: email.trim(),
      satisfactionRating: rating,
      featureInterests: Array.from(features),
      comments: comments.trim(),
    };
    try { await onSubmit?.(answers); setSubmitted(true); }
    finally { setIsSubmitting(false); }
  };

  const ratingLabel = ratingOptions.find(r => r.value === rating)?.label ?? rating;
  const featureLabels = Array.from(features)
    .map(v => featureOptions.find(f => f.value === v)?.label ?? v)
    .join(', ') || 'None selected';

  const progressPct = (Math.min(step, 3) + 1) / 4 * 100;

  const renderStepContent = () => {
    if (submitted) return (
      <div style={motionEnabled ? { animation: animation.scaleIn } : {}}>
        <Stack direction="vertical" gap={16} align="center">
          <div style={{ width: 64, height: 64, borderRadius: 'var(--ggui-shape-radius-full,9999px)', background: 'var(--ggui-color-primary-600,#0284c7)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Icon name="check" size={32} color="#ffffff" />
          </div>
          <Text variant="h2" align="center" color="var(--ggui-color-primary-800,#075985)">Thank you!</Text>
          <Text align="center" color="var(--ggui-color-neutral-500,#6b7280)">Your survey response has been submitted successfully.</Text>
        </Stack>
      </div>
    );
    if (step === 4) return (
      <div style={anim}>
        <Stack direction="vertical" gap={0}>
          <div style={{ background: 'var(--ggui-color-primary-50,#f0f9ff)', border: '1px solid var(--ggui-color-primary-200,#bae6fd)', borderRadius: 'var(--ggui-shape-radius-md,8px)', padding: 'var(--ggui-spacing-2,8px) var(--ggui-spacing-4,16px)', marginBottom: 'var(--ggui-spacing-4,16px)' }}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-primary-800,#075985)">Review your answers before submitting</Text>
          </div>
          <ReviewRow label="Name" value={name} />
          <ReviewRow label="Email" value={email} />
          <ReviewRow label="Satisfaction" value={ratingLabel} />
          <ReviewRow label="Feature Interests" value={featureLabels} />
          <ReviewRow label="Comments" value={comments || 'No comments provided'} />
        </Stack>
      </div>
    );
    if (step === 0) return (
      <div style={anim}>
        <Stack direction="vertical" gap={16} role="group" aria-label="Personal information">
          <Text color="var(--ggui-color-neutral-500,#6b7280)">Tell us a bit about yourself.</Text>
          <Stack direction="vertical" gap={4}>
            <Input id="sname" label="Full Name" placeholder="Jane Smith" value={name}
              onChange={v => { setName(v); if (touched.name) setNameError(validateName(v)); }}
              error={nameError} required aria-required="true" aria-invalid={!!nameError}
              aria-describedby={nameError ? 'sname-err' : undefined}
              onBlur={() => { setTouched(t => ({ ...t, name: true })); setNameError(validateName(name)); }}
            />
            {nameError && <Text id="sname-err" variant="caption" color="var(--ggui-color-error-500,#ef4444)" role="alert">{nameError}</Text>}
          </Stack>
          <Stack direction="vertical" gap={4}>
            <Input id="semail" label="Email Address" type="email" placeholder="jane@example.com" value={email}
              onChange={v => { setEmail(v); if (touched.email) setEmailError(validateEmail(v)); }}
              error={emailError} required aria-required="true" aria-invalid={!!emailError}
              aria-describedby={emailError ? 'semail-err' : undefined}
              onBlur={() => { setTouched(t => ({ ...t, email: true })); setEmailError(validateEmail(email)); }}
            />
            {emailError && <Text id="semail-err" variant="caption" color="var(--ggui-color-error-500,#ef4444)" role="alert">{emailError}</Text>}
          </Stack>
        </Stack>
      </div>
    );
    if (step === 1) return (
      <div style={anim}>
        <Stack direction="vertical" gap={16}>
          <Text color="var(--ggui-color-neutral-500,#6b7280)">How satisfied are you with our product overall?</Text>
          <RadioGroup label="Satisfaction Rating" value={rating} onChange={setRating} options={ratingOptions} direction="vertical" />
        </Stack>
      </div>
    );
    if (step === 2) return (
      <div style={anim}>
        <Stack direction="vertical" gap={16}>
          <Text color="var(--ggui-color-neutral-500,#6b7280)">Which features interest you most? Select all that apply.</Text>
          <div role="group" aria-label="Feature interests" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(190px,1fr))', gap: 'var(--ggui-spacing-2,8px)' }}>
            {featureOptions.map(opt => (
              <div key={opt.value} style={{ padding: 'var(--ggui-spacing-2,8px) var(--ggui-spacing-4,16px)', borderRadius: 'var(--ggui-shape-radius-md,8px)', border: features.has(opt.value) ? '2px solid var(--ggui-color-primary-400,#38bdf8)' : '2px solid var(--ggui-color-neutral-200,#e5e7eb)', background: features.has(opt.value) ? 'var(--ggui-color-primary-50,#f0f9ff)' : 'transparent', transition: transition.colors }}>
                <Checkbox label={opt.label} checked={features.has(opt.value)} onChange={checked => {
                  setFeatures(prev => { const n = new Set(prev); checked ? n.add(opt.value) : n.delete(opt.value); return n; });
                }} />
              </div>
            ))}
          </div>
        </Stack>
      </div>
    );
    if (step === 3) return (
      <div style={anim}>
        <Stack direction="vertical" gap={8}>
          <Text color="var(--ggui-color-neutral-500,#6b7280)">Any additional thoughts? (Optional)</Text>
          <TextArea id="scomments" label="Comments" placeholder="Tell us anything else…" value={comments}
            onChange={v => { if (v.length <= MAX_CHARS) setComments(v); }}
            rows={5} maxLength={MAX_CHARS} aria-describedby="char-counter"
          />
          <Row justify="end">
            <Text id="char-counter" variant="caption" aria-live="polite" aria-atomic="true"
              color={comments.length >= MAX_CHARS ? 'var(--ggui-color-error-500,#ef4444)' : comments.length >= MAX_CHARS * 0.8 ? 'var(--ggui-color-warning-500,#f59e0b)' : 'var(--ggui-color-neutral-500,#6b7280)'}>
              {comments.length} / {MAX_CHARS}
            </Text>
          </Row>
        </Stack>
      </div>
    );
    return null;
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4,16px)">
      <MotionKeyframes />
      {/* Header */}
      <div style={{ background: 'linear-gradient(135deg,var(--ggui-color-primary-600,#0284c7),var(--ggui-color-primary-800,#075985))', borderRadius: 'var(--ggui-shape-radius-lg,12px) var(--ggui-shape-radius-lg,12px) 0 0', padding: 'var(--ggui-spacing-6,24px)' }}>
        <Stack direction="vertical" gap={4}>
          <Text variant="h2" color="#ffffff" weight="bold">{title}</Text>
          <Text color="var(--ggui-color-primary-200,#bae6fd)">{subtitle}</Text>
        </Stack>
      </div>
      {/* Body */}
      <Card padding="var(--ggui-spacing-6,24px)" shadow="md" style={{ borderRadius: '0 0 var(--ggui-shape-radius-lg,12px) var(--ggui-shape-radius-lg,12px)', borderTop: 'none' } as React.CSSProperties}>
        <Stack direction="vertical" gap={24}>
          {/* Progress */}
          {!submitted && (
            <Stack direction="vertical" gap={10}>
              <Row justify="between" align="center">
                <Text variant="caption" color="var(--ggui-color-primary-700,#0369a1)" weight="semibold">
                  Step {Math.min(step + 1, 4)} of 4
                </Text>
                <Badge variant="primary" size="sm">{STEP_LABELS[Math.min(step, 3)]}</Badge>
              </Row>
              <div role="progressbar" aria-valuenow={Math.min(step + 1, 4)} aria-valuemin={1} aria-valuemax={4} aria-label="Survey progress" style={{ width: '100%', height: 8, borderRadius: 'var(--ggui-shape-radius-full,9999px)', background: 'var(--ggui-color-primary-100,#e0f2fe)', overflow: 'hidden' }}>
                <div style={{ height: '100%', width: progressPct + '%', borderRadius: 'var(--ggui-shape-radius-full,9999px)', background: 'linear-gradient(to right,var(--ggui-color-primary-400,#38bdf8),var(--ggui-color-primary-600,#0284c7))', transition: 'width 400ms cubic-bezier(0.4,0,0.2,1)' }} />
              </div>
              <Row justify="between">
                {STEP_LABELS.map((label, i) => (
                  <Stack key={label} direction="vertical" align="center" gap={4}>
                    <div aria-hidden="true" style={{ width: 28, height: 28, borderRadius: 'var(--ggui-shape-radius-full,9999px)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 'var(--ggui-font-size-xs,12px)', fontWeight: 'var(--ggui-font-weight-semibold,600)', transition: transition.colors, background: i < Math.min(step, 4) ? 'var(--ggui-color-primary-600,#0284c7)' : i === Math.min(step, 3) ? 'var(--ggui-color-primary-500,#0ea5e9)' : 'var(--ggui-color-neutral-200,#e5e7eb)', color: i <= Math.min(step, 3) ? '#ffffff' : 'var(--ggui-color-neutral-500,#6b7280)', boxShadow: i === Math.min(step, 3) ? '0 0 0 3px var(--ggui-color-primary-200,#bae6fd)' : 'none' }}>
                      {i < Math.min(step, 4) ? <Icon name="check" size={14} /> : (i + 1).toString()}
                    </div>
                    <Text variant="caption" color={i === Math.min(step, 3) ? 'var(--ggui-color-primary-700,#0369a1)' : 'var(--ggui-color-neutral-500,#6b7280)'} weight={i === Math.min(step, 3) ? 'semibold' : 'normal'}>{label}</Text>
                  </Stack>
                ))}
              </Row>
            </Stack>
          )}
          {!submitted && <Divider margin={0} />}
          <div style={{ minHeight: 220 }}>{renderStepContent()}</div>
          {!submitted && (
            <>
              <Divider margin={0} />
              <Row justify="between" align="center">
                {step > 0
                  ? <Button variant="outline" onClick={() => setStep(s => s - 1)} leftIcon={<Icon name="chevron-left" size={16} />} aria-label="Previous step">Back</Button>
                  : <div />}
                {step < 4
                  ? <Button variant="primary" onClick={handleNext} disabled={!canNext} rightIcon={<Icon name="chevron-right" size={16} />}>{step === 3 ? 'Review Answers' : 'Next'}</Button>
                  : <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting} aria-busy={isSubmitting} leftIcon={isSubmitting ? undefined : <Icon name="check" size={16} />}>{isSubmitting ? 'Submitting…' : 'Submit Survey'}</Button>}
              </Row>
            </>
          )}
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useCallback } from 'react';
import { Stack, Row, Text, Input, Select, Button, Badge, Icon, Spacer, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

type Column = 'todo' | 'inprogress' | 'done';
type Priority = 'low' | 'medium' | 'high';

export interface Task {
  id: string;
  title: string;
  priority: Priority;
  assignee: string;
  dueDate?: string;
  column: Column;
}

export interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
}

const COLUMNS: { id: Column; label: string; accent: string; bg: string; border: string }[] = [
  { id: 'todo',       label: 'To Do',      accent: 'var(--ggui-color-neutral-500,#6b7280)',    bg: 'var(--ggui-color-neutral-100,#f3f4f6)',  border: 'var(--ggui-color-neutral-200,#e5e7eb)' },
  { id: 'inprogress', label: 'In Progress', accent: 'var(--ggui-color-primary-600,#0284c7)',   bg: 'var(--ggui-color-primary-50,#f0f9ff)',   border: 'var(--ggui-color-primary-200,#bae6fd)' },
  { id: 'done',       label: 'Done',        accent: 'var(--ggui-color-success-600,#16a34a)',   bg: 'var(--ggui-color-neutral-50,#f9fafb)',   border: 'var(--ggui-color-success-500,#22c55e)' },
];

const PRIORITY_MAP: Record<Priority, 'error' | 'warning' | 'success'> = {
  high: 'error', medium: 'warning', low: 'success',
};

const PRIORITY_OPTS = [
  { value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' },
];

const COL_OPTS = COLUMNS.map(c => ({ value: c.id, label: c.label }));

function genId() { return Math.random().toString(36).slice(2, 10); }

function fmtDate(iso: string) {
  const d = new Date(iso + 'T00:00:00');
  return d.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
}

function getInitials(name: string) {
  return name.split(' ').map((w: string) => w[0] ?? '').slice(0, 2).join('').toUpperCase();
}

const AVATAR_COLORS = [
  'var(--ggui-color-primary-600,#0284c7)',
  'var(--ggui-color-success-600,#16a34a)',
  'var(--ggui-color-warning-600,#d97706)',
  'var(--ggui-color-error-500,#ef4444)',
];

const DEFAULT_TASKS: Task[] = [
  { id:'t1', title:'Design landing page mockups', priority:'high',   assignee:'Alex Rivera', dueDate:'2025-07-15', column:'todo'       },
  { id:'t2', title:'Set up CI/CD pipeline',        priority:'medium', assignee:'Jordan Lee',  dueDate:'2025-07-18', column:'todo'       },
  { id:'t3', title:'Write API documentation',      priority:'low',    assignee:'Sam Chen',                         column:'todo'       },
  { id:'t4', title:'Implement auth flow',           priority:'high',   assignee:'Alex Rivera', dueDate:'2025-07-10', column:'inprogress' },
  { id:'t5', title:'Database schema migration',    priority:'medium', assignee:'Morgan Kim',  dueDate:'2025-07-12', column:'inprogress' },
  { id:'t6', title:'Fix navbar responsive bug',    priority:'low',    assignee:'Jordan Lee',                        column:'inprogress' },
  { id:'t7', title:'Onboarding email templates',   priority:'medium', assignee:'Sam Chen',    dueDate:'2025-07-05', column:'done'       },
  { id:'t8', title:'User research interviews',     priority:'high',   assignee:'Morgan Kim',  dueDate:'2025-07-01', column:'done'       },
];

/* ── Avatar ── */
function Avatar({ name }: { name: string }) {
  const bg = AVATAR_COLORS[name.length % AVATAR_COLORS.length];
  return (
    <div title={name} aria-label={'Assigned to ' + name} style={{
      width:28, height:28, borderRadius:'var(--ggui-shape-radius-full,9999px)',
      background:bg, color:'#fff', display:'flex', alignItems:'center', justifyContent:'center',
      fontSize:'var(--ggui-font-size-xs,12px)', fontWeight:'var(--ggui-font-weight-semibold,600)',
      flexShrink:0, border:'2px solid var(--ggui-color-neutral-50,#f9fafb)',
    }}>
      {getInitials(name)}
    </div>
  );
}

/* ── Add Task Form ── */
function AddTaskForm({ onAdd, onCancel }: { onAdd:(t:string,p:Priority)=>void; onCancel:()=>void }) {
  const [title,setTitle]       = useState('');
  const [priority,setPriority] = useState<Priority>('medium');
  return (
    <div role="form" aria-label="Add new task" style={{
      background:'var(--ggui-color-primary-50,#f0f9ff)', border:'1px solid var(--ggui-color-primary-200,#bae6fd)',
      borderRadius:'var(--ggui-shape-radius-md,8px)', padding:'var(--ggui-spacing-2,8px)',
      animation:'ggui-slideInDown 180ms ease-out both',
    }}>
      <Stack direction="vertical" gap={8}>
        <Input label="Task title" placeholder="What needs to be done?" value={title} onChange={setTitle} required />
        <Select label="Priority" value={priority} onChange={(v) => setPriority(v as Priority)} options={PRIORITY_OPTS} />
        <Row gap={8}>
          <Button variant="primary" size="sm" onClick={() => { if(title.trim()){ onAdd(title.trim(), priority); } }} disabled={!title.trim()} fullWidth>Add Task</Button>
          <Button variant="ghost" size="sm" onClick={onCancel} fullWidth>Cancel</Button>
        </Row>
      </Stack>
    </div>
  );
}

/* ── Task Card ── */
function TaskCard({ task, onMove, onEdit, onDelete, isNew }: {
  task:Task; onMove:(id:string,col:Column)=>void;
  onEdit:(id:string,t:string,p:Priority)=>void; onDelete:(id:string)=>void; isNew:boolean;
}) {
  const [editing,setEditing]     = useState(false);
  const [editTitle,setEditTitle] = useState(task.title);
  const [editPri,setEditPri]     = useState<Priority>(task.priority);
  const { motionEnabled } = useMotion();

  const saveEdit = () => {
    if (!editTitle.trim()) return;
    onEdit(task.id, editTitle.trim(), editPri);
    setEditing(false);
  };

  const moveTargets = COL_OPTS.filter(c => c.value !== task.column);

  const cardStyle: React.CSSProperties = {
    background:'var(--ggui-color-neutral-50,#ffffff)',
    border:'1px solid var(--ggui-color-neutral-200,#e5e7eb)',
    borderRadius:'var(--ggui-shape-radius-md,8px)',
    padding:'var(--ggui-spacing-2,8px) var(--ggui-spacing-4,16px)',
    boxShadow:'var(--ggui-shape-shadow-sm,0 1px 2px rgba(0,0,0,0.05))',
    animation: isNew && motionEnabled ? animation.slideInDown : 'none',
  };

  if (editing) return (
    <div style={cardStyle}>
      <Stack direction="vertical" gap={8}>
        <Input label="Title" value={editTitle} onChange={setEditTitle} required />
        <Select label="Priority" value={editPri} onChange={(v)=>setEditPri(v as Priority)} options={PRIORITY_OPTS} />
        <Row gap={8}>
          <Button variant="primary" size="xs" onClick={saveEdit} disabled={!editTitle.trim()}>Save</Button>
          <Button variant="ghost" size="xs" onClick={()=>{ setEditTitle(task.title); setEditPri(task.priority); setEditing(false); }}>Cancel</Button>
        </Row>
      </Stack>
    </div>
  );

  const btnBase: React.CSSProperties = {
    background:'none', border:'1px solid var(--ggui-color-neutral-200,#e5e7eb)',
    borderRadius:'var(--ggui-shape-radius-sm,4px)', padding:'2px 6px', cursor:'pointer',
    fontSize:'var(--ggui-font-size-xs,12px)', color:'var(--ggui-color-neutral-700,#374151)',
    whiteSpace:'nowrap' as const,
  };

  return (
    <div style={cardStyle}>
      <Stack direction="vertical" gap={6}>
        <div onDoubleClick={()=>setEditing(true)} style={{ cursor:'pointer' }} title="Double-click to edit">
          <Text weight="medium" color={task.column==='done' ? 'var(--ggui-color-neutral-400,#9ca3af)' : 'var(--ggui-color-neutral-900,#111827)'}>
            {task.title}
          </Text>
        </div>
        <Row gap={8} align="center">
          <Badge variant={PRIORITY_MAP[task.priority]} size="sm" pill>
            {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
          </Badge>
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-neutral-500,#6b7280)">
              {'📅 ' + fmtDate(task.dueDate)}
            </Text>
          )}
          <Spacer />
          <Avatar name={task.assignee} />
        </Row>
        <Row gap={6} align="center" wrap>
          <button aria-label={'Edit: ' + task.title} onClick={()=>setEditing(true)} style={{ ...btnBase, color:'var(--ggui-color-primary-600,#0284c7)' }}>✏️ Edit</button>
          {moveTargets.map(t => (
            <button key={t.value} aria-label={'Move to ' + t.label} onClick={()=>onMove(task.id, t.value as Column)} style={btnBase}>
              {'→ ' + t.label}
            </button>
          ))}
          <Spacer />
          <button aria-label={'Delete: ' + task.title} onClick={()=>onDelete(task.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'var(--ggui-color-neutral-300,#d1d5db)', padding:2, display:'flex', alignItems:'center' }}>
            <Icon name="x" size={14} />
          </button>
        </Row>
      </Stack>
    </div>
  );
}

/* ── Kanban Column ── */
function KanbanColumn({ col, tasks, newIds, onMove, onEdit, onDelete, onAdd }: {
  col: typeof COLUMNS[number]; tasks: Task[]; newIds: Set<string>;
  onMove:(id:string,c:Column)=>void; onEdit:(id:string,t:string,p:Priority)=>void;
  onDelete:(id:string)=>void; onAdd:(t:string,p:Priority)=>void;
}) {
  const [showForm, setShowForm] = useState(false);

  return (
    <div style={{
      flex:'1 1 260px', minWidth:260, display:'flex', flexDirection:'column',
      background:'var(--ggui-color-neutral-100,#f3f4f6)',
      borderRadius:'var(--ggui-shape-radius-lg,12px)', border:'1px solid ' + col.border, overflow:'hidden',
    }}>
      {/* Header */}
      <div style={{
        background: col.bg, borderBottom:'2px solid ' + col.border,
        padding:'var(--ggui-spacing-2,8px) var(--ggui-spacing-4,16px)',
        display:'flex', alignItems:'center', gap:8,
      }}>
        <div style={{ width:10, height:10, borderRadius:'var(--ggui-shape-radius-full,9999px)', background:col.accent, flexShrink:0 }} />
        <Text weight="semibold" color={col.accent}>{col.label}</Text>
        <Spacer />
        <div style={{
          background: col.accent, color:'#fff',
          borderRadius:'var(--ggui-shape-radius-full,9999px)', minWidth:22, height:22,
          display:'flex', alignItems:'center', justifyContent:'center',
          fontSize:'var(--ggui-font-size-xs,12px)', fontWeight:'var(--ggui-font-weight-semibold,600)', padding:'0 6px',
        }} aria-label={tasks.length + ' tasks in ' + col.label}>
          {tasks.length}
        </div>
      </div>

      {/* Task list */}
      <div role="list" aria-label={col.label + ' tasks'} style={{
        flex:1, padding:'var(--ggui-spacing-2,8px)',
        display:'flex', flexDirection:'column', gap:'var(--ggui-spacing-2,8px)', overflowY:'auto',
      }}>
        {tasks.length === 0 && (
          <div style={{ textAlign:'center', padding:'var(--ggui-spacing-6,24px) 0', color:'var(--ggui-color-neutral-300,#d1d5db)', fontSize:'var(--ggui-font-size-sm,14px)' }}>No tasks yet</div>
        )}
        {tasks.map(task => (
          <div key={task.id} role="listitem">
            <TaskCard task={task} onMove={onMove} onEdit={onEdit} onDelete={onDelete} isNew={newIds.has(task.id)} />
          </div>
        ))}
        {showForm && (
          <AddTaskForm onAdd={(t,p)=>{ onAdd(t,p); setShowForm(false); }} onCancel={()=>setShowForm(false)} />
        )}
      </div>

      {/* Add button */}
      {!showForm && (
        <div style={{ padding:'var(--ggui-spacing-2,8px)', borderTop:'1px solid ' + col.border }}>
          <button onClick={()=>setShowForm(true)} aria-label={'Add task to ' + col.label} style={{
            width:'100%', background:'none', border:'1px dashed ' + col.border,
            borderRadius:'var(--ggui-shape-radius-md,8px)',
            padding:'var(--ggui-spacing-1,4px) var(--ggui-spacing-2,8px)',
            cursor:'pointer', color:col.accent,
            fontSize:'var(--ggui-font-size-sm,14px)', fontWeight:'var(--ggui-font-weight-medium,500)',
            display:'flex', alignItems:'center', justifyContent:'center', gap:6,
          }}>
            <Icon name="plus" size={14} color={col.accent} />
            Add Task
          </button>
        </div>
      )}
    </div>
  );
}

/* ── Root ── */
export default function GeneratedComponent({ initialTasks = DEFAULT_TASKS, onTaskUpdate }: Props) {
  const [tasks,    setTasks]    = useState<Task[]>(initialTasks);
  const [newIds,   setNewIds]   = useState<Set<string>>(new Set());
  const { motionEnabled } = useMotion();

  const notify = useCallback((t: Task[]) => onTaskUpdate?.(t), [onTaskUpdate]);

  const handleMove = useCallback((id:string, col:Column) => {
    setTasks(prev => { const n = prev.map(t => t.id===id ? {...t,column:col} : t); notify(n); return n; });
  },[notify]);

  const handleEdit = useCallback((id:string, title:string, priority:Priority) => {
    setTasks(prev => { const n = prev.map(t => t.id===id ? {...t,title,priority} : t); notify(n); return n; });
  },[notify]);

  const handleDelete = useCallback((id:string) => {
    setTasks(prev => { const n = prev.filter(t => t.id!==id); notify(n); return n; });
  },[notify]);

  const handleAdd = useCallback((column:Column, title:string, priority:Priority) => {
    const id = genId();
    const task: Task = { id, title, priority, assignee:'Unassigned', column };
    setNewIds(prev => new Set([...prev, id]));
    setTasks(prev => { const n = [...prev, task]; notify(n); return n; });
    setTimeout(() => setNewIds(prev => { const s = new Set(prev); s.delete(id); return s; }), 700);
  },[notify]);

  const total    = tasks.length;
  const done     = tasks.filter(t => t.column==='done').length;
  const inprog   = tasks.filter(t => t.column==='inprogress').length;
  const pct      = total > 0 ? Math.round((done/total)*100) : 0;

  return (
    <>
      <MotionKeyframes />
      <div style={{ display:'flex', flexDirection:'column', gap:'var(--ggui-spacing-4,16px)', padding:'var(--ggui-spacing-4,16px)' }}>

        {/* Summary bar */}
        <div role="region" aria-label="Task board summary" style={{
          background:'linear-gradient(135deg,var(--ggui-color-primary-700,#0369a1),var(--ggui-color-primary-500,#0ea5e9))',
          borderRadius:'var(--ggui-shape-radius-lg,12px)',
          padding:'var(--ggui-spacing-4,16px) var(--ggui-spacing-6,24px)',
          color:'#fff',
          animation: motionEnabled ? animation.fadeIn : 'none',
        }}>
          <div style={{ display:'flex', flexWrap:'wrap', alignItems:'center', gap:'var(--ggui-spacing-4,16px)' }}>
            <div>
              <div style={{ fontSize:'var(--ggui-font-size-lg,18px)', fontWeight:'var(--ggui-font-weight-bold,700)' }}>Task Board</div>
              <div style={{ fontSize:'var(--ggui-font-size-sm,14px)', opacity:0.85, marginTop:2 }}>Track your team's progress</div>
            </div>
            <div style={{ display:'flex', gap:'var(--ggui-spacing-6,24px)', marginLeft:'auto', flexWrap:'wrap' }}>
              {[['Total',total],['In Progress',inprog],['Done',done]].map(([lbl,val]) => (
                <div key={String(lbl)} style={{ textAlign:'center' }}>
                  <div style={{ fontSize:'var(--ggui-font-size-2xl,24px)', fontWeight:'var(--ggui-font-weight-bold,700)' }}>{val}</div>
                  <div style={{ fontSize:'var(--ggui-font-size-xs,12px)', opacity:0.8 }}>{lbl}</div>
                </div>
              ))}
            </div>
          </div>
          <div style={{ marginTop:'var(--ggui-spacing-4,16px)' }}>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:'var(--ggui-font-size-xs,12px)', opacity:0.9, marginBottom:6 }}>
              <span>Completion</span><span>{pct}%</span>
            </div>
            <div role="progressbar" aria-valuenow={pct} aria-valuemin={0} aria-valuemax={100} aria-label={pct + '% completed'} style={{
              height:8, background:'rgba(255,255,255,0.25)', borderRadius:'var(--ggui-shape-radius-full,9999px)', overflow:'hidden',
            }}>
              <div style={{ height:'100%', width:pct+'%', background:'rgba(255,255,255,0.85)', borderRadius:'var(--ggui-shape-radius-full,9999px)', transition:'width 500ms ease' }} />
            </div>
          </div>
        </div>

        {/* Columns */}
        <div role="region" aria-label="Kanban board" style={{ display:'flex', gap:'var(--ggui-spacing-4,16px)', alignItems:'flex-start', flexWrap:'wrap' }}>
          {COLUMNS.map((col,i) => (
            <div key={col.id} style={{ flex:'1 1 260px', minWidth:260, animation: motionEnabled ? ('ggui-slideInUp 260ms ease-out ' + (i*70) + 'ms both') : 'none' }}>
              <KanbanColumn
                col={col}
                tasks={tasks.filter(t => t.column === col.id)}
                newIds={newIds}
                onMove={handleMove}
                onEdit={handleEdit}
                onDelete={handleDelete}
                onAdd={(t,p) => handleAdd(col.id, t, p)}
              />
            </div>
          ))}
        </div>
      </div>
    </>
  );
}

import { useState, useEffect, useCallback } from 'react';
import {
  Container, Card, Stack, Row, Text, Button, Badge, Tabs,
  Divider, Box, MotionKeyframes, useMotion, Icon, Spacer
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Specification { key: string; value: string; }
interface Review { id: string; author: string; rating: number; text: string; date: string; }

export interface Props {
  productId?: string;
  name?: string;
  description?: string;
  price?: number;
  currency?: string;
  currencySymbol?: string;
  rating?: number;
  reviewCount?: number;
  stock?: number;
  imageColor?: string;
  specifications?: Specification[];
  reviews?: Review[];
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

const DEFAULT_SPECS: Specification[] = [
  { key: 'Brand', value: 'TechCraft' },
  { key: 'Model', value: 'TC-PRO-2024' },
  { key: 'Weight', value: '1.2 kg' },
  { key: 'Dimensions', value: '30 × 20 × 5 cm' },
  { key: 'Material', value: 'Aerospace-grade aluminium' },
  { key: 'Warranty', value: '2 years' },
  { key: 'Color', value: 'Midnight Blue' },
  { key: 'Connectivity', value: 'Bluetooth 5.3, USB-C' },
];

const DEFAULT_REVIEWS: Review[] = [
  { id: '1', author: 'Alexandra M.', rating: 5, text: 'Outstanding build quality! Worth every penny.', date: 'Dec 14, 2024' },
  { id: '2', author: 'James T.', rating: 4, text: 'Great product. Setup was easy and performance exceeded expectations.', date: 'Dec 2, 2024' },
  { id: '3', author: 'Priya S.', rating: 5, text: 'Second time buying from this brand. Consistent quality and fast shipping.', date: 'Nov 28, 2024' },
];

function fmtPrice(amount: number, symbol: string, currency: string): string {
  try {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency, currencyDisplay: 'narrowSymbol' }).format(amount);
  } catch {
    return symbol + amount.toFixed(2);
  }
}

function Stars({ rating, size = 18 }: { rating: number; size?: number }) {
  return (
    <Row gap={2} align="center">
      {[1, 2, 3, 4, 5].map((s) => (
        <span key={s} aria-hidden="true" style={{
          color: rating >= s ? 'var(--ggui-color-warning-500, #f59e0b)' : rating >= s - 0.5 ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)',
          fontSize: size, lineHeight: 1, opacity: rating >= s ? 1 : rating >= s - 0.5 ? 0.5 : 1,
        }}>★</span>
      ))}
    </Row>
  );
}

function SpecsTable({ specs }: { specs: Specification[] }) {
  return (
    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 'var(--ggui-font-size-sm, 14px)' }} aria-label="Product specifications">
      <tbody>
        {specs.map((s, i) => (
          <tr key={s.key} style={{ background: i % 2 === 0 ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-neutral-50, #f9fafb)', borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
            <td style={{ padding: '8px 16px', fontWeight: 600, color: 'var(--ggui-color-primary-800, #075985)', width: '40%', borderRight: '2px solid var(--ggui-color-primary-200, #bae6fd)' }}>{s.key}</td>
            <td style={{ padding: '8px 16px', color: 'var(--ggui-color-neutral-700, #374151)' }}>{s.value}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

function ReviewList({ reviews }: { reviews: Review[] }) {
  if (!reviews.length) return <Text align="center" color="var(--ggui-color-neutral-500, #6b7280)">No reviews yet.</Text>;
  return (
    <Stack direction="vertical" gap={12}>
      {reviews.map((r) => (
        <div key={r.id} style={{ padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', background: 'var(--ggui-color-neutral-50, #f9fafb)' }}>
          <Stack direction="vertical" gap={8}>
            <Row align="center" gap={8} wrap>
              <div aria-hidden="true" style={{ width: 36, height: 36, borderRadius: '50%', background: 'linear-gradient(135deg, var(--ggui-color-primary-400, #38bdf8), var(--ggui-color-primary-600, #0284c7))', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 700, fontSize: 14, flexShrink: 0 }}>
                {r.author.charAt(0).toUpperCase()}
              </div>
              <Stack direction="vertical" gap={2}>
                <Text weight="semibold" color="var(--ggui-color-neutral-900, #111827)">{r.author}</Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{r.date}</Text>
              </Stack>
              <Spacer />
              <Stars rating={r.rating} size={14} />
            </Row>
            <Text color="var(--ggui-color-neutral-700, #374151)">{r.text}</Text>
          </Stack>
        </div>
      ))}
    </Stack>
  );
}

function QtySelector({ qty, max, disabled, onChange }: { qty: number; max: number; disabled: boolean; onChange: (n: number) => void }) {
  const btnStyle = (active: boolean) => ({
    width: 40, height: 40, border: 'none', cursor: active ? 'pointer' : 'not-allowed' as const,
    background: active ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-neutral-100, #f3f4f6)',
    color: active ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-300, #d1d5db)',
    fontSize: 20, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', transition: transition.colors,
  });
  return (
    <div role="group" aria-label="Quantity selector" style={{ display: 'inline-flex', alignItems: 'center', border: '2px solid var(--ggui-color-primary-200, #bae6fd)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', overflow: 'hidden' }}>
      <button onClick={() => onChange(Math.max(1, qty - 1))} disabled={disabled || qty <= 1} aria-label="Decrease quantity" style={btnStyle(!disabled && qty > 1)}>−</button>
      <span aria-live="polite" style={{ minWidth: 48, textAlign: 'center', fontWeight: 600, fontSize: 16, color: 'var(--ggui-color-neutral-900, #111827)', padding: '0 8px', background: 'var(--ggui-color-neutral-50, #f9fafb)', lineHeight: '38px', borderLeft: '1px solid var(--ggui-color-primary-200, #bae6fd)', borderRight: '1px solid var(--ggui-color-primary-200, #bae6fd)' }}>{qty}</span>
      <button onClick={() => onChange(Math.min(max, qty + 1))} disabled={disabled || qty >= max} aria-label="Increase quantity" style={btnStyle(!disabled && qty < max)}>+</button>
    </div>
  );
}

