import { useState, useEffect, useRef, useCallback } from 'react';
import { MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ChatUser { id: string; name: string; }
interface ChatMessage { id: string; sender: string; senderId?: string; text: string; timestamp: string; }
interface AgentEvent { type: 'message' | 'typing'; sender: string; senderId?: string; text?: string; timestamp?: string; }

interface Props {
  title?: string;
  participantCount?: number;
  currentUser?: ChatUser;
  initialMessages?: ChatMessage[];
  onSend?: (data: { text: string; timestamp: string }) => void;
}

function fmt(ts: string): string {
  try { return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }
  catch { return ts; }
}

function initials(name: string): string {
  return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
}

function Avatar({ name, self: isSelf }: { name: string; self: boolean }) {
  return (
    <div aria-hidden="true" style={{
      width: 32, height: 32, minWidth: 32,
      borderRadius: 'var(--ggui-shape-radius-full,9999px)',
      background: isSelf
        ? 'linear-gradient(135deg,var(--ggui-color-primary-500,#0ea5e9),var(--ggui-color-primary-700,#0369a1))'
        : 'var(--ggui-color-neutral-300,#d1d5db)',
      color: isSelf ? '#fff' : 'var(--ggui-color-neutral-700,#374151)',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      fontSize: 'var(--ggui-font-size-xs,12px)',
      fontWeight: 'var(--ggui-font-weight-semibold,600)',
      flexShrink: 0,
    }}>{initials(name)}</div>
  );
}

function TypingDots() {
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 4,
      background: 'var(--ggui-color-neutral-100,#f3f4f6)',
      border: '1px solid var(--ggui-color-neutral-200,#e5e7eb)',
      borderRadius: 'var(--ggui-shape-radius-lg,12px)', padding: '10px 14px',
