}

function Bubble({ msg, isSelf, motion, delay }: { msg: ChatMessage; isSelf: boolean; motion: boolean; delay: number; }) {
  const r = 'var(--ggui-shape-radius-lg,12px)';
  const rs = 'var(--ggui-shape-radius-sm,4px)';
  return (
