/* Controlled text state via ref — reads input element value directly from event currentTarget */
function useTextInput(initial = '') {
  const [value, setValue] = useState(initial);
  const clear = useCallback(() => setValue(''), []);
  const onInput = useCallback((ev: React.FormEvent<HTMLInputElement>) => {
    setValue((ev.currentTarget as HTMLInputElement).value);
  }, []);
  return { value, clear, onInput };
}

