            aria-label="Current conditions details"
          >
            <Stack gap={2}>
              <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">HUMIDITY</Text>
              <Text weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" />
            <Stack gap={2}>
              <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">WIND</Text>
              <Text weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">{windSpeed} mph</Text>
            </Stack>
          </Row>

          <Divider margin={0} />

          {/* 5-Day Forecast */}
          <Stack gap={16}>
            <Text variant="label" weight="bold" color="var(--ggui-color-neutral-700, #374151)">
              5-Day Forecast
            </Text>
            <Row justify="between" align="center" wrap>
              {forecast.map((day, index) => {
                const delay = (index * 50) + 'ms';
                return (
                  <Stack 
                    key={day.day} 
                    align="center" 
                    gap={8}
                    style={{ 
                      flex: '1 1 60px',
