}

import { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button,
  Divider,
  MotionKeyframes,
  useMotion,
  Icon,
  Badge
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Labels for the 1-5 satisfaction scale */
  satisfactionLabels?: { value: string; label: string }[];
  /** List of features for the interest group */
  featureOptions?: { value: string; label: string }[];
  /** Callback for final submission */
  onSubmit?: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  featureInterests: string[];
  comments: string;
}

export default function GeneratedComponent({
  satisfactionLabels = [
    { value: '1', label: 'Very Dissatisfied' },
    { value: '2', label: 'Dissatisfied' },
    { value: '3', label: 'Neutral' },
    { value: '4', label: 'Satisfied' },
    { value: '5', label: 'Very Satisfied' },
  ],
  featureOptions = [
    { value: 'ui', label: 'User Interface' },
    { value: 'performance', label: 'Performance' },
    { value: 'security', label: 'Security' },
    { value: 'integration', label: 'Integrations' },
    { value: 'reporting', label: 'Advanced Reporting' },
  ],
  onSubmit
}: Props) {
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    featureInterests: [],
    comments: '',
  });

  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const totalSteps = 5; // 4 steps + 1 review

  // Validation Logic
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const errors = useMemo(() => {
    const errs: Record<string, string> = {};
    if (!formData.name.trim()) errs.name = 'Name is required';
    if (!formData.email.trim()) {
      errs.email = 'Email is required';
    } else if (!emailRegex.test(formData.email)) {
      errs.email = 'Please enter a valid email address';
    }
    if (step === 2 && !formData.satisfaction) errs.satisfaction = 'Please select a rating';
    return errs;
  }, [formData, step]);

  const isStepValid = useMemo(() => {
    switch (step) {
      case 1:
        return !!formData.name.trim() && emailRegex.test(formData.email);
      case 2:
        return !!formData.satisfaction;
      case 3:
        return true; 
      case 4:
        return formData.comments.length <= 500;
      default:
        return true;
    }
  }, [step, formData]);

  const handleNext = () => {
    if (isStepValid && step < totalSteps) {
      setStep(s => s + 1);
    }
  };

  const handleBack = () => {
    if (step > 1) {
      setStep(s => s - 1);
    }
  };

  const handleSubmit = () => {
    if (onSubmit) {
      onSubmit(formData);
    }
  };

  const updateField = (field: keyof SurveyData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const toggleFeature = (val: string) => {
    const current = [...formData.featureInterests];
    const index = current.indexOf(val);
    if (index > -1) {
      current.splice(index, 1);
    } else {
      current.push(val);
    }
    updateField('featureInterests', current);
  };

  // Progress Bar Component
  const ProgressBar = () => {
    const progressWidth = (step / totalSteps) * 100 + '%';
    return (
      <Stack gap={12} margin="0 0 var(--ggui-spacing-8) 0">
        <Row justify="between" align="center">
          <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">
            Step {step} of {totalSteps}
          </Text>
          <Badge variant="primary">
            {Math.round((step / totalSteps) * 100)}% Complete
          </Badge>
        </Row>
        <div style={{
          height: '8px',
          backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          overflow: 'hidden',
          position: 'relative'
        }}>
          <div style={{
            position: 'absolute',
            left: 0,
            top: 0,
            bottom: 0,
            width: progressWidth,
            backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
            transition: transition.normal,
            borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          }} />
        </div>
      </Stack>
    );
  };

  const Heading = ({ level, children }: { level: 1 | 2 | 3 | 4; children: React.ReactNode }) => (
    <Text
      variant={level === 1 ? 'h1' : level === 2 ? 'h2' : 'h3'}
      weight="bold"
      color="var(--ggui-color-primary-900, #0c4a6e)"
    >
      {children}
    </Text>
  );

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" border={false}>
        <Stack gap={32} role="form" aria-label="Survey Form Wizard">
          <ProgressBar />

          <div style={{ minHeight: '300px' }}>
            {step === 1 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Stack gap={4}>
                  <Heading level={2}>Welcome!</Heading>
                  <Text color="var(--ggui-color-neutral-500, #6b7280)">Let's start with your basic information.</Text>
                </Stack>
                <Input
                  id="survey-name"
                  label="Full Name"
                  placeholder="Jane Doe"
                  value={formData.name}
                  onChange={(v) => updateField('name', v)}
                  required
                  error={touched.name ? errors.name : undefined}
                />
                <Input
                  id="survey-email"
                  label="Email Address"
                  type="email"
                  placeholder="jane@example.com"
                  value={formData.email}
                  onChange={(v) => updateField('email', v)}
                  required
                  error={touched.email ? errors.email : undefined}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Stack gap={4}>
                  <Heading level={2}>Satisfaction</Heading>
                  <Text color="var(--ggui-color-neutral-500, #6b7280)">How would you rate your overall experience?</Text>
                </Stack>
                <RadioGroup
                  label="Rating"
                  value={formData.satisfaction}
                  onChange={(v) => updateField('satisfaction', v)}
                  options={satisfactionLabels}
                  error={touched.satisfaction ? errors.satisfaction : undefined}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Stack gap={4}>
                  <Heading level={2}>Feature Interests</Heading>
                  <Text color="var(--ggui-color-neutral-500, #6b7280)">Which features are you most interested in?</Text>
                </Stack>
                <Stack gap={12}>
                  {featureOptions.map(opt => (
                    <Checkbox
                      key={opt.value}
                      label={opt.label}
                      checked={formData.featureInterests.includes(opt.value)}
                      onChange={() => toggleFeature(opt.value)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Stack gap={4}>
                  <Heading level={2}>Additional Comments</Heading>
                  <Text color="var(--ggui-color-neutral-500, #6b7280)">Is there anything else you'd like to share?</Text>
                </Stack>
                <Stack gap={4}>
                  <TextArea
                    label="Comments"
                    placeholder="Tell us more..."
                    value={formData.comments}
                    onChange={(v) => updateField('comments', v)}
                    maxLength={500}
                    rows={6}
                  />
                  <Row justify="end">
                    <Text variant="caption" color={formData.comments.length > 500 ? 'var(--ggui-color-error-600, #dc2626)' : 'var(--ggui-color-neutral-500, #6b7280)'}>
                      {formData.comments.length} / 500
                    </Text>
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                <Stack gap={4}>
                  <Heading level={2}>Review Your Answers</Heading>
                  <Text color="var(--ggui-color-neutral-500, #6b7280)">Please double-check everything before submitting.</Text>
                </Stack>

                <Card padding="var(--ggui-spacing-6, 24px)" border background="var(--ggui-color-primary-50, #f0f9ff)">
                  <Stack gap={16}>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Name</Text>
                      <Text weight="medium">{formData.name}</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Email</Text>
                      <Text weight="medium">{formData.email}</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Satisfaction</Text>
                      <Text weight="medium">
                        {satisfactionLabels.find(l => l.value === formData.satisfaction)?.label || 'Not selected'}
                      </Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Feature Interests</Text>
                      <Row wrap gap={8}>
                        {formData.featureInterests.length > 0 ? (
                          formData.featureInterests.map(val => (
                            <Badge key={val} variant="secondary">
                              {featureOptions.find(o => o.value === val)?.label || val}
                            </Badge>
                          ))
                        ) : (
                          <Text color="var(--ggui-color-neutral-500, #6b7280)">None selected</Text>
                        )}
                      </Row>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Comments</Text>
                      <Text weight="medium">{formData.comments || 'No comments'}</Text>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>

          <Divider />

          <Row justify="between" align="center">
            <Button
              variant="outline"
              onClick={handleBack}
              disabled={step === 1}
              leftIcon={<Icon name="chevron-left" size={16} />}
            >
              Back
            </Button>

            {step < totalSteps ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!isStepValid}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleSubmit}
                leftIcon={<Icon name="check" size={16} />}
              >
                Submit Survey
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useEffect, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Icon,
  Divider,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

type Priority = 'low' | 'medium' | 'high';
type Status = 'To Do' | 'In Progress' | 'Done';

interface Task {
  id: string;
  title: string;
  priority: Priority;
  assignee: {
    name: string;
    initials: string;
  };
  dueDate?: string;
  status: Status;
}

interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
}

const DEFAULT_TASKS: Task[] = [
  {
    id: '1',
    title: 'Design system review',
    priority: 'high',
    assignee: { name: 'John Doe', initials: 'JD' },
    dueDate: '2023-12-25',
    status: 'To Do',
  },
  {
    id: '2',
    title: 'Implement Kanban board',
    priority: 'medium',
    assignee: { name: 'Jane Smith', initials: 'JS' },
    dueDate: '2023-12-20',
    status: 'In Progress',
  },
  {
    id: '3',
    title: 'Setup project boilerplate',
    priority: 'low',
    assignee: { name: 'Bob Wilson', initials: 'BW' },
    dueDate: '2023-12-15',
    status: 'Done',
  },
];

const COLUMNS: Status[] = ['To Do', 'In Progress', 'Done'];

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

const PRIORITY_TOKEN_MAP = {
  low: 'var(--ggui-color-info-500, #06b6d4)',
  medium: 'var(--ggui-color-warning-500, #f59e0b)',
  high: 'var(--ggui-color-error-500, #ef4444)',
};

export default function GeneratedComponent({ 
  initialTasks = DEFAULT_TASKS,
  onTaskUpdate 
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingToColumn, setAddingToColumn] = useState<Status | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>('medium');

  const { motionEnabled } = useMotion();

  const handleUpdate = (updatedTasks: Task[]) => {
    setTasks(updatedTasks);
    onTaskUpdate?.(updatedTasks);
  };

  const addTask = (status: Status) => {
    if (!newTaskTitle.trim()) return;

    const newTask: Task = {
      id: Math.random().toString(36).substring(2, 9),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: { name: 'Unassigned', initials: '??' },
      status,
    };

    handleUpdate([...tasks, newTask]);
    setNewTaskTitle('');
    setAddingToColumn(null);
  };

  const moveTask = (taskId: string, newStatus: Status) => {
    handleUpdate(tasks.map(t => t.id === taskId ? { ...t, status: newStatus } : t));
  };

  const updateTaskTitle = (taskId: string, newTitle: string) => {
    handleUpdate(tasks.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
    setEditingTaskId(null);
  };

  const stats = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter(t => t.status === 'Done').length;
    const percentage = total > 0 ? (completed / total) * 100 : 0;
    return { total, completed, percentage };
  }, [tasks]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />

      <Stack gap={24}>
        {/* Header / Summary Bar */}
        <Card padding="var(--ggui-spacing-4, 16px)" border shadow="sm">
          <Row justify="between" align="center" wrap>
            <Stack gap={4}>
              <Text variant="h2" weight="bold">Project Board</Text>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                Manage your team's workflow and tasks
              </Text>
            </Stack>

            <Row gap={16} align="center">
              <Stack gap={2} align="end">
                <Text variant="label" weight="semibold">Overall Progress</Text>
                <Row gap={8} align="center">
                  <div style={{ 
                    width: 120, 
                    height: 8, 
                    background: 'var(--ggui-color-neutral-200, #e5e7eb)', 
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    overflow: 'hidden'
                  }}>
                    <div style={{ 
                      width: stats.percentage + '%', 
                      height: '100%', 
                      background: 'var(--ggui-color-success-500, #22c55e)',
                      transition: transition.normal
                    }} />
                  </div>
                  <Text variant="caption" weight="bold">
                    {stats.completed} / {stats.total}
                  </Text>
                </Row>
              </Stack>
            </Row>
          </Row>
        </Card>

        {/* Board Columns */}
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
          gap: 'var(--ggui-spacing-6, 24px)',
          alignItems: 'start'
        }}>
          {COLUMNS.map((columnStatus) => (
            <KanbanColumn
              key={columnStatus}
              status={columnStatus}
              tasks={tasks.filter(t => t.status === columnStatus)}
              isAdding={addingToColumn === columnStatus}
              onAddClick={() => setAddingToColumn(columnStatus)}
              onCancelAdd={() => setAddingToColumn(null)}
              newTaskTitle={newTaskTitle}
              onNewTaskTitleChange={setNewTaskTitle}
              newTaskPriority={newTaskPriority}
              onNewTaskPriorityChange={setNewTaskPriority}
              onSaveTask={() => addTask(columnStatus)}
              editingTaskId={editingTaskId}
              onEditTask={setEditingTaskId}
              onMoveTask={moveTask}
              onUpdateTitle={updateTaskTitle}
              motionEnabled={motionEnabled}
            />
          ))}
        </div>
      </Stack>
    </Container>
  );
}

interface ColumnProps {
  status: Status;
  tasks: Task[];
  isAdding: boolean;
  onAddClick: () => void;
  onCancelAdd: () => void;
  newTaskTitle: string;
  onNewTaskTitleChange: (v: string) => void;
  newTaskPriority: Priority;
  onNewTaskPriorityChange: (v: Priority) => void;
  onSaveTask: () => void;
  editingTaskId: string | null;
  onEditTask: (id: string | null) => void;
  onMoveTask: (id: string, s: Status) => void;
  onUpdateTitle: (id: string, t: string) => void;
  motionEnabled: boolean;
}

function KanbanColumn({
  status,
  tasks,
  isAdding,
  onAddClick,
  onCancelAdd,
  newTaskTitle,
  onNewTaskTitleChange,
  newTaskPriority,
  onNewTaskPriorityChange,
  onSaveTask,
  editingTaskId,
  onEditTask,
  onMoveTask,
  onUpdateTitle,
  motionEnabled
}: ColumnProps) {
  return (
    <Stack gap={16} style={{ 
      background: 'var(--ggui-color-neutral-100, #f3f4f6)', 
      padding: 'var(--ggui-spacing-4, 16px)', 
      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      minHeight: 400
    }}>
      {/* Column Header */}
      <Row justify="between" align="center" style={{ paddingBottom: 'var(--ggui-spacing-2, 8px)' }}>
        <Row gap={8} align="center">
          <Text variant="h3" weight="bold" color="var(--ggui-color-neutral-700, #374151)">{status}</Text>
          <Badge variant="secondary" size="sm">{tasks.length}</Badge>
        </Row>
      </Row>

      {/* Task List */}
      <Stack gap={12}>
        {tasks.map((task, index) => (
          <TaskCard
            key={task.id}
            task={task}
            isEditing={editingTaskId === task.id}
            onEdit={() => onEditTask(task.id)}
            onCancelEdit={() => onEditTask(null)}
            onSaveTitle={(title) => onUpdateTitle(task.id, title)}
            onMove={(newStatus) => onMoveTask(task.id, newStatus)}
            index={index}
            motionEnabled={motionEnabled}
          />
        ))}

        {/* Add Task Form */}
        {isAdding ? (
          <Card padding="var(--ggui-spacing-4, 16px)" border shadow="md" style={{ animation: motionEnabled ? animation.scaleIn : 'none' }}>
            <Stack gap={12}>
              <Input
                label="Task Title"
                placeholder="What needs to be done?"
                value={newTaskTitle}
                onChange={onNewTaskTitleChange}
                required
              />
              <Select
                label="Priority"
                value={newTaskPriority}
                onChange={(v) => onNewTaskPriorityChange(v as Priority)}
                options={PRIORITY_OPTIONS}
              />
              <Row gap={8} justify="end">
                <Button size="sm" variant="ghost" onClick={onCancelAdd}>Cancel</Button>
                <Button size="sm" variant="primary" onClick={onSaveTask} disabled={!newTaskTitle.trim()}>
                  Add Task
                </Button>
              </Row>
            </Stack>
          </Card>
        ) : (
          <Button 
            variant="ghost" 
            fullWidth 
            onClick={onAddClick}
            leftIcon={<Icon name="plus" size={16} />}
            style={{ 
              border: '1px dashed var(--ggui-color-neutral-300, #d1d5db)',
              color: 'var(--ggui-color-neutral-500, #6b7280)',
              background: 'transparent'
            }}
          >
            Add Task
          </Button>
        )}
      </Stack>
    </Stack>
  );
}

interface TaskCardProps {
  task: Task;
  isEditing: boolean;
  onEdit: () => void;
  onCancelEdit: () => void;
  onSaveTitle: (title: string) => void;
  onMove: (status: Status) => void;
  index: number;
  motionEnabled: boolean;
}

function TaskCard({
  task,
  isEditing,
  onEdit,
  onCancelEdit,
  onSaveTitle,
  onMove,
  index,
  motionEnabled
}: TaskCardProps) {
  const [editValue, setEditValue] = useState(task.title);

  useEffect(() => {
    if (isEditing) setEditValue(task.title);
  }, [isEditing, task.title]);

  const priorityVariantMap = {
    low: 'info' as const,
    medium: 'warning' as const,
    high: 'error' as const,
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') onSaveTitle(editValue);
    if (e.key === 'Escape') onCancelEdit();
  };

  return (
    <Card 
      padding="var(--ggui-spacing-4, 16px)" 
      shadow="sm"
      style={{ 
        cursor: 'default',
        animation: motionEnabled ? animation.slideInUp : 'none',
        animationDelay: motionEnabled ? (index * 50) + 'ms' : '0ms',
        transition: transition.colors,
        borderLeft: '4px solid ' + PRIORITY_TOKEN_MAP[task.priority]
      }}
    >
      <Stack gap={12}>
        <Row justify="between" align="start">
          <Badge variant={priorityVariantMap[task.priority]} size="sm">
            {task.priority.toUpperCase()}
          </Badge>

          <Row gap={4}>
            <Button 
              size="xs" 
              variant="ghost" 
              onClick={onEdit}
              aria-label="Edit task"
            >
              <Icon name="settings" size={14} />
            </Button>
          </Row>
        </Row>

        {isEditing ? (
          <Stack gap={8}>
            <Input
              label="Edit Title"
              value={editValue}
              onChange={setEditValue}
              onKeyDown={handleKeyDown}
            />
            <Row gap={4} justify="end">
              <Button size="xs" variant="ghost" onClick={onCancelEdit}>Cancel</Button>
              <Button size="xs" variant="primary" onClick={() => onSaveTitle(editValue)}>Save</Button>
            </Row>
          </Stack>
        ) : (
          <Text 
            weight="medium" 
            onDoubleClick={onEdit}
            style={{ cursor: 'pointer' }}
          >
            {task.title}
          </Text>
        )}

        <Divider />

        <Row justify="between" align="center" wrap>
          <Row gap={8} align="center">
            <div style={{
              width: 28,
              height: 28,
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              background: 'var(--ggui-color-primary-100, #e0f2fe)',
              color: 'var(--ggui-color-primary-700, #0369a1)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 'var(--ggui-font-size-xs, 12px)',
              fontWeight: 'bold'
            }} title={task.assignee.name}>
              {task.assignee.initials}
            </div>
            {task.dueDate && (
              <Row gap={4} align="center">
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  {task.dueDate}
                </Text>
              </Row>
            )}
          </Row>

          <div style={{ minWidth: 120 }}>
            <Select
              label="Status"
              value={task.status}
              onChange={(v) => onMove(v as Status)}
              size="sm"
              options={COLUMNS.map(c => ({ value: c, label: c }))}
            />
          </div>
        </Row>
      </Stack>
    </Card>
  );
}

