function ElementCell({ 
  element, 
  onClick, 
  isSelected 
}: { 
  element: ElementData; 
  onClick: () => void; 
  isSelected: boolean;
  isMatch: boolean;
}) {
  const categoryColor = CATEGORY_COLORS[element.category] || CATEGORY_COLORS['unknown'];
  const isDark = ['alkali metal', 'actinide', 'lanthanide', 'noble gas'].includes(element.category);

  return (
    <button
      onClick={onClick}
      aria-label={element.name + ", atomic number " + element.number}
      style={{
        gridColumn: element.xpos,
        gridRow: element.ypos,
        aspectRatio: '1/1',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '2px',
        cursor: 'pointer',
        border: isSelected 
          ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
          : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
        backgroundColor: isSelected ? 'var(--ggui-color-primary-50, #f0f9ff)' : categoryColor,
        color: isDark ? 'white' : 'var(--ggui-color-neutral-900, #111827)',
        transition: transition.normal,
        boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
        transform: isSelected ? 'scale(1.1)' : 'scale(1)',
        zIndex: isSelected ? 10 : 1,
        outline: 'none',
        position: 'relative'
      }}
    >
      <div style={{ position: 'absolute', top: 2, left: 2 }}>
        <Text style={{ fontSize: '8px', lineHeight: 1, fontWeight: '700', color: 'inherit' }}>
          {element.number}
        </Text>
      </div>
      <Text style={{ 
        fontSize: 'var(--ggui-font-size-base, 16px)', 
        fontWeight: 'var(--ggui-font-weight-bold, 700)',
        lineHeight: 1,
        color: 'inherit'
      }}>
        {element.symbol}
      </Text>
    </button>
  );
}

function DetailCard({ element, onClose }: { element: ElementData; onClose: () => void }) {
  const categoryColor = CATEGORY_COLORS[element.category] || CATEGORY_COLORS['unknown'];
  const isDark = ['alkali metal', 'actinide', 'lanthanide', 'noble gas'].includes(element.category);

  return (
    <Card padding={0} style={{ overflow: 'hidden', boxShadow: 'var(--ggui-shape-shadow-lg)', border: 'none' }}>
      {/* Element Identity Card */}
      <Box style={{ 
        backgroundColor: categoryColor, 
        padding: 'var(--ggui-spacing-8, 32px)', 
        color: isDark ? 'white' : 'var(--ggui-color-neutral-900, #111827)',
        textAlign: 'center',
        position: 'relative'
      }}>
        <div style={{ position: 'absolute', top: 12, right: 12 }}>
          <Button variant="ghost" size="sm" onClick={onClose} aria-label="Close" style={{ color: 'inherit', minWidth: 'auto', padding: '4px' }}>
            ×
          </Button>
        </div>

        <Text style={{ fontSize: '14px', fontWeight: 'bold', opacity: 0.8 }}>ATOMIC NO. {element.number}</Text>
        <Text style={{ fontSize: '64px', fontWeight: '900', margin: '8px 0', lineHeight: 1, letterSpacing: '-0.02em' }}>
          {element.symbol}
        </Text>
        <Text variant="h2" weight="bold" style={{ textTransform: 'uppercase' }}>{element.name}</Text>

        <Box style={{ marginTop: 16 }}>
          <Badge variant="secondary" style={{ 
            background: 'rgba(255,255,255,0.2)', 
            color: 'inherit',
            backdropFilter: 'blur(4px)',
            border: '1px solid rgba(255,255,255,0.3)'
          }}>
            {element.category}
          </Badge>
        </Box>
      </Box>

      {/* Details List */}
      <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-neutral-50, #f9fafb)">
        <Stack gap={16}>
          <DetailRow label="Atomic Weight" value={element.weight} />
          <Divider />
          <DetailRow label="Configuration" value={element.electron_configuration || 'Unknown'} />
          <Divider />
          <DetailRow label="Period" value={element.ypos} />
          <DetailRow label="Group" value={element.xpos} />
          <Divider />
          <Stack gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" weight="semibold">APPEARANCE</Text>
            <Text style={{ fontSize: '14px' }}>{element.appearance || 'Standard state description not available.'}</Text>
          </Stack>
        </Stack>
      </Box>
    </Card>
  );
}

function DetailRow({ label, value }: { label: string; value: string | number }) {
  return (
    <Row justify="between" align="center">
      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" weight="semibold" style={{ textTransform: 'uppercase' }}>
        {label}
      </Text>
      <Text weight="bold">{value}</Text>
    </Row>
  );
}

function Legend({ categories }: { categories: string[] }) {
  return (
    <Box padding="var(--ggui-spacing-2, 8px)" style={{ 
      background: 'var(--ggui-color-neutral-50, #f9fafb)', 
      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
      border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
      maxWidth: '400px'
    }}>
      <Row gap={12} wrap justify="center">
        {categories.map(cat => (
          <Row key={cat} gap={4} align="center">
            <Box style={{ 
              width: 10, 
              height: 10, 
              borderRadius: '2px', 
              background: CATEGORY_COLORS[cat] || CATEGORY_COLORS['unknown'] 
            }} />
            <Text style={{ fontSize: '10px', textTransform: 'capitalize', whiteSpace: 'nowrap' }} weight="medium">
              {cat}
            </Text>
          </Row>
        ))}
      </Row>
