      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{ marginLeft: 'var(--ggui-spacing-1, 4px)' }}>
        ({rating.toFixed(1)})
      </Text>
    </Row>
  );
};

