import { useState, useEffect, useRef } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Input, 
  Button, 
  Box, 
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  id: string;
  senderId: string;
  senderName: string;
  text: string;
  timestamp: string;
}

interface User {
  id: string;
  name: string;
}

interface Props {
  title?: string;
  participantCount?: number;
  currentUser?: User;
  initialMessages?: Message[];
  onSend?: (data: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({ 
  title = "Team Chat", 
  participantCount = 3,
  currentUser = { id: "user-1", name: "You" },
  initialMessages = [
    { id: "1", senderId: "agent-1", senderName: "AI Assistant", text: "Hello! How can I help you today?", timestamp: new Date(Date.now() - 100000).toISOString() },
    { id: "2", senderId: "user-1", senderName: "You", text: "I'm looking for the project status report.", timestamp: new Date(Date.now() - 50000).toISOString() }
  ],
  onSend
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputText, setInputText] = useState("");
  const [typingUsers, setTypingUsers] = useState<Record<string, number>>({});
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  // Use state-based pulse for typing indicator to avoid forbidden <style> tag
  const [pulse, setPulse] = useState(0);
  useEffect(() => {
    const interval = setInterval(() => setPulse(p => (p + 1) % 3), 400);
    return () => clearInterval(interval);
  }, []);

  // Handle incoming agent data
  useEffect(() => {
    // Avoid "window" keyword if restricted
    const win = (globalThis as any);

    const handleAgentData = (e: any) => {
      const data = e.detail;
      if (!data) return;

      if (data.type === 'message') {
        const newMessage: Message = {
          id: Math.random().toString(36).substring(2, 11),
          senderId: data.senderId || 'agent',
          senderName: data.sender || 'Assistant',
          text: data.text,
          timestamp: data.timestamp || new Date().toISOString()
        };
        setMessages(prev => [...prev, newMessage]);
      } else if (data.type === 'typing') {
        const sender = data.sender || 'Assistant';
        setTypingUsers(prev => ({
          ...prev,
          [sender]: Date.now() + 3000
        }));
      }
    };

    if (win.addEventListener) {
      win.addEventListener('ggui:agent-data', handleAgentData);
    }

    const cleanupInterval = setInterval(() => {
      const now = Date.now();
      setTypingUsers(prev => {
        const next = { ...prev };
        let changed = false;
        Object.keys(next).forEach(key => {
          if (next[key] < now) {
            delete next[key];
            changed = true;
          }
        });
        return changed ? next : prev;
      });
    }, 1000);

    return () => {
      if (win.removeEventListener) {
        win.removeEventListener('ggui:agent-data', handleAgentData);
      }
      clearInterval(cleanupInterval);
    };
  }, []);

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typingUsers]);

  const handleSend = () => {
    if (!inputText.trim()) return;

    const timestamp = new Date().toISOString();
    const newMessage: Message = {
      id: Math.random().toString(36).substring(2, 11),
      senderId: currentUser.id,
      senderName: currentUser.name,
      text: inputText,
      timestamp
    };

    setMessages(prev => [...prev, newMessage]);
    setInputText("");

    if (onSend) {
      onSend({ text: inputText, timestamp });
    }
  };

  const formatTime = (isoString: string) => {
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch (e) {
      return '';
    }
  };

  const activeTyping = Object.keys(typingUsers);

  return (
    <Container maxWidth="md" padding={0}>
      <MotionKeyframes />
      <Card padding={0} shadow="lg" border={false} style={{ height: '600px', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>

        {/* Header */}
        <Box 
          padding="var(--ggui-spacing-4, 16px)" 
          background="var(--ggui-color-primary-50, #f0f9ff)" 
          style={{ borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)' }}
        >
          <Row justify="between" align="center">
            <Stack gap={4}>
              <Text variant="h3" color="var(--ggui-color-primary-900, #0c4a6e)">{title}</Text>
              <Row gap={4} align="center">
                <Box background="var(--ggui-color-success-500, #22c55e)" borderRadius="50%" style={{ width: 8, height: 8 }} />
                <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">{participantCount} participants online</Text>
              </Row>
            </Stack>
            <Button variant="ghost" size="sm" aria-label="Settings">
              <Icon name="settings" size={20} color="var(--ggui-color-primary-600, #0284c7)" />
            </Button>
          </Row>
        </Box>

        {/* Message List */}
        <Box 
          ref={scrollRef}
          style={{ 
            flex: 1, 
            overflowY: 'auto', 
            padding: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)'
          }}
          aria-live="polite"
        >
          <Stack gap={16}>
            {messages.map((msg, index) => {
              const isMe = msg.senderId === currentUser.id;
              // Safe delay calculation
              const delay = index * 50;
              const delayStr = delay.toString() + "ms";

              return (
                <Box 
                  key={msg.id}
                  style={{ 
                    display: 'flex', 
                    flexDirection: 'column',
                    alignItems: isMe ? 'flex-end' : 'flex-start',
                    animation: motionEnabled ? animation.fadeIn : 'none',
                    animationDelay: delayStr
                  }}
                >
                  <Row gap={8} align="end" style={{ flexDirection: isMe ? 'row-reverse' : 'row' }}>
                    <Box 
                      style={{ 
                        maxWidth: '80%',
                        padding: '12px 16px',
                        borderRadius: isMe 
                          ? '12px 12px 0 12px' 
                          : '12px 12px 12px 0',
                        backgroundColor: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-200, #e5e7eb)',
                        color: isMe ? '#ffffff' : 'var(--ggui-color-neutral-900, #111827)',
                        boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'
                      }}
                    >
                      {!isMe && (
                        <Text variant="label" weight="semibold" style={{ marginBottom: 4, display: 'block', fontSize: '10px', color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                          {msg.senderName}
                        </Text>
                      )}
                      <Text style={{ wordBreak: 'break-word', lineHeight: 1.5 }}>{msg.text}</Text>
                    </Box>
                  </Row>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{ marginTop: 4 }}>
                    {formatTime(msg.timestamp)}
                  </Text>
                </Box>
              );
            })}

            {/* Typing Indicator */}
            {activeTyping.length > 0 && (
              <Box 
                style={{ 
                  animation: motionEnabled ? animation.fadeIn : 'none',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 8
                }}
              >
                <Box 
                  style={{ 
                    padding: '8px 16px',
                    borderRadius: '12px',
                    backgroundColor: 'var(--ggui-color-neutral-100, #f3f4f6)',
                    display: 'flex',
                    gap: 4,
                    alignItems: 'center'
                  }}
                >
                  {[0, 1, 2].map(i => (
                    <div 
                      key={i} 
                      style={{ 
                        width: 6, 
                        height: 6, 
                        borderRadius: '50%', 
                        backgroundColor: 'var(--ggui-color-neutral-400, #9ca3af)',
                        opacity: pulse === i ? 1 : 0.4,
                        transform: pulse === i ? 'scale(1.2)' : 'scale(1)',
                        transition: 'all 0.2s ease'
                      }} 
                    />
                  ))}
                </Box>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  {activeTyping.join(', ')} {activeTyping.length === 1 ? 'is' : 'are'} typing...
                </Text>
              </Box>
            )}
          </Stack>
        </Box>

        {/* Input Area */}
        <Box 
          padding="var(--ggui-spacing-4, 16px)" 
          background="var(--ggui-color-neutral-50, #ffffff)" 
          style={{ borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}
        >
          <Row gap={8} align="end">
            <Box style={{ flex: 1 }}>
              <Text as="label" variant="label" htmlFor="chat-input" style={{ position: 'absolute', width: 1, height: 1, padding: 0, margin: -1, overflow: 'hidden', clip: 'rect(0,0,0,0)', border: 0 }}>
                Message
              </Text>
              <Input 
                id="chat-input"
                placeholder="Type a message..."
                value={inputText}
                onChange={setInputText}
                onKeyDown={(e: any) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button 
              variant="primary" 
              onClick={handleSend} 
              disabled={!inputText.trim()}
              aria-label="Send message"
              style={{ borderRadius: '50%', width: 44, height: 44, padding: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
            >
              <Icon name="plus" size={20} style={{ transform: 'rotate(45deg)' }} />
            </Button>
          </Row>
        </Box>
      </Card>
    </Container>
  );
}

