import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, TextArea, Button, Divider, RadioGroup, Checkbox } from '@ggui-ai/design/primitives';

interface Props {
  ratingLabels?: { [key: string]: string };
  featureOptions?: { value: string; label: string }[];
  onSubmit: (data: any) => void;
}

export default function GeneratedComponent({
  ratingLabels = { '1': 'Very Dissatisfied', '2': 'Dissatisfied', '3': 'Neutral', '4': 'Satisfied', '5': 'Very Satisfied' },
  featureOptions = [
    { value: 'ui', label: 'User Interface' },
    { value: 'perf', label: 'Performance' },
    { value: 'docs', label: 'Documentation' },
    { value: 'support', label: 'Support' },
  ],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    rating: '',
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = () => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.rating !== '';
    return true;
  };

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'name' || field === 'email') {
      setErrors((prev) => ({ ...prev, [field]: '' }));
    }
  };

  const handleNext = () => {
    if (step === 1) {
      const nameError = formData.name.trim() === '' ? 'Name is required' : '';
      const emailError = !validateEmail(formData.email) ? 'Valid email is required' : '';
      if (nameError || emailError) {
        setErrors({ name: nameError, email: emailError });
        return;
      }
    }
    setStep(step + 1);
  };

  const handlePrev = () => setStep(step - 1);

  const toggleFeature = (val: string, checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      features: checked ? [...prev.features, val] : prev.features.filter((f) => f !== val),
    }));
  };

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Input label="Name" value={formData.name} onChange={(v) => updateField('name', v)} required error={errors.name} />
            <Input label="Email" type="email" value={formData.email} onChange={(v) => updateField('email', v)} required error={errors.email} />
          </Stack>
        );
      case 2:
        return (
          <RadioGroup
            label="How satisfied are you with our service?"
            value={formData.rating}
            onChange={(v) => updateField('rating', v)}
            options={Object.entries(ratingLabels).map(([value, label]) => ({ value, label }))}
          />
        );
      case 3:
        return (
          <Stack gap={8}>
            <Text variant="label">Features you are interested in:</Text>
            {featureOptions.map((opt) => (
              <Checkbox
                key={opt.value}
                label={opt.label}
                checked={formData.features.includes(opt.value)}
                onChange={(checked) => toggleFeature(opt.value, checked)}
              />
            ))}
          </Stack>
        );
      case 4:
        return (
          <Stack gap={8}>
            <TextArea
              label="Comments"
              value={formData.comments}
              onChange={(v) => updateField('comments', v)}
              maxLength={500}
            />
            <Text variant="caption" color="var(--ggui-color-neutral-500)">
              {formData.comments.length} / 500 characters
            </Text>
          </Stack>
        );
      case 5:
        return (
          <Stack gap={8}>
            <Text variant="h3">Review your answers</Text>
            <Divider />
            <Text>Name: {formData.name}</Text>
            <Text>Email: {formData.email}</Text>
            <Text>Rating: {ratingLabels[formData.rating] || formData.rating}</Text>
            <Text>Features: {formData.features.map(f => featureOptions.find(o => o.value === f)?.label).join(', ') || 'None'}</Text>
            <Text>Comments: {formData.comments || 'No comments'}</Text>
          </Stack>
        );
    }
  };

  return (
    <Container maxWidth="md">
      <Card>
        <Stack role="form" aria-label="Survey Form" gap={24}>
          <Stack align="center" gap={8}>
            <Text variant="h3" color="var(--ggui-color-primary-600)">Survey Form</Text>
            <Text>Step {Math.min(step, 5)} of 5</Text>
          </Stack>
          <Divider />
          {renderStep()}
          <Divider />
          <Row justify="between">
            <Button variant="outline" onClick={handlePrev} disabled={step === 1}>Back</Button>
            {step < 5 ? (
              <Button onClick={handleNext} disabled={!isStepValid()}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onSubmit(formData)}>Submit</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Button, Input, Select, Badge, Icon } from '@ggui-ai/design/primitives';

interface Task {
  id: string;
  title: string;
  column: 'todo' | 'inprogress' | 'done';
  priority: 'low' | 'medium' | 'high';
}

interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (task: Task) => void;
}

export default function GeneratedComponent({ initialTasks = [], onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<Task['priority']>('medium');

  const moveTask = (taskId: string, newColumn: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: newColumn as Task['column'] } : t);
    setTasks(updatedTasks);
    onTaskUpdate?.(updatedTasks.find(t => t.id === taskId)!);
  };

  const addTask = (column: string) => {
    if (!newTitle.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTitle,
      column: column as Task['column'],
      priority: newPriority,
    };
    setTasks([...tasks, newTask]);
    setNewTitle('');
    setAddingTo(null);
    onTaskUpdate?.(newTask);
  };

  const getPriorityColor = (p: Task['priority']): any => {
    switch (p) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      default: return 'success';
    }
  };

  return (
    <Container>
      <Row justify="between" style={{ padding: 'var(--ggui-spacing-4, 16px)', background: 'var(--ggui-color-neutral-50, #f9fafb)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
        <Text variant="h2">Project Board</Text>
        <Stack direction="horizontal" gap={16}>
          <Text>Total: {tasks.length}</Text>
          <Text>Done: {tasks.filter(t => t.column === 'done').length}</Text>
        </Stack>
      </Row>

      <Stack direction="horizontal" gap={16} align="start" style={{ marginTop: 'var(--ggui-spacing-4, 16px)' }}>
        {['todo', 'inprogress', 'done'].map(col => (
          <Stack key={col} style={{ flex: 1, backgroundColor: 'var(--ggui-color-neutral-100, #f3f4f6)', padding: 'var(--ggui-spacing-2, 8px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
            <Text weight="semibold" style={{ padding: 'var(--ggui-spacing-2, 8px)' }}>{col.toUpperCase()} ({tasks.filter(t => t.column === col).length})</Text>

            <Stack gap={8}>
              {tasks.filter(t => t.column === col).map(task => (
                <Card key={task.id} shadow="sm">
                  <Stack gap={8}>
                    <Text>{task.title}</Text>
                    <Badge variant={getPriorityColor(task.priority)}>{task.priority}</Badge>
                    <Select 
                      label="Move task"
                      value={task.column} 
                      onChange={(v) => moveTask(task.id, v)}
                      options={[
                        { value: 'todo', label: 'To Do' },
                        { value: 'inprogress', label: 'In Progress' },
                        { value: 'done', label: 'Done' }
                      ]}
                    />
                  </Stack>
                </Card>
              ))}
            </Stack>

            {addingTo === col ? (
              <Stack gap={8} style={{ padding: 'var(--ggui-spacing-2, 8px)' }}>
                <Input label="Task title" value={newTitle} onChange={setNewTitle} />
                <Select label="Priority" value={newPriority} onChange={(v) => setNewPriority(v as Task['priority'])} options={[
                  { value: 'low', label: 'Low' },
                  { value: 'medium', label: 'Medium' },
                  { value: 'high', label: 'High' }
                ]} />
                <Button variant="primary" onClick={() => addTask(col)}>Add</Button>
                <Button variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
              </Stack>
            ) : (
              <Button variant="ghost" onClick={() => setAddingTo(col)} leftIcon={<Icon name="plus" size={16} />}>Add Task</Button>
            )}
          </Stack>
        ))}
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, Button, Badge, Modal } from '@ggui-ai/design/primitives';

interface Element {
  number: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  electronConfiguration: string;
  period: number;
  group: number;
}

const CATEGORIES = {
  'Alkali Metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  'Alkaline Earth Metal': 'var(--ggui-color-primary-400, #38bdf8)',
  'Transition Metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'Noble Gas': 'var(--ggui-color-success-500, #22c55e)',
  'Other': 'var(--ggui-color-neutral-300, #d1d5db)',
};

const elementsData: Element[] = [
  { number: 1, symbol: 'H', name: 'Hydrogen', atomicWeight: 1.008, category: 'Other', electronConfiguration: '1s1', period: 1, group: 1 },
  { number: 2, symbol: 'He', name: 'Helium', atomicWeight: 4.0026, category: 'Noble Gas', electronConfiguration: '1s2', period: 1, group: 18 },
  { number: 3, symbol: 'Li', name: 'Lithium', atomicWeight: 6.94, category: 'Alkali Metal', electronConfiguration: '[He] 2s1', period: 2, group: 1 },
  { number: 4, symbol: 'Be', name: 'Beryllium', atomicWeight: 9.0122, category: 'Alkaline Earth Metal', electronConfiguration: '[He] 2s2', period: 2, group: 2 },
  { number: 26, symbol: 'Fe', name: 'Iron', atomicWeight: 55.845, category: 'Transition Metal', electronConfiguration: '[Ar] 3d6 4s2', period: 4, group: 8 },
];

export default function PeriodicTable({ elements = elementsData }: { elements?: Element[] }) {
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filtered = elements.filter(
    (e) => e.name.toLowerCase().includes(search.toLowerCase()) || e.symbol.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <Container>
      <Stack gap={16}>
        <Input label="Search Element" value={search} onChange={setSearch} placeholder="Search by name or symbol" />

        <Row gap={8} wrap>
          {Object.entries(CATEGORIES).map(([cat, color]) => (
            <Badge key={cat} style={{ background: color }}>{cat}</Badge>
          ))}
        </Row>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1, 4px)' }}>
          {filtered.map((el) => (
            <Card
              key={el.number}
              padding={4}
              onClick={() => setSelectedElement(el)}
              style={{
                cursor: 'pointer',
                background: CATEGORIES[el.category as keyof typeof CATEGORIES] || CATEGORIES['Other'],
                minHeight: '60px',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center'
              }}
            >
              <Text variant="caption" style={{ alignSelf: 'start' }}>{el.number}</Text>
              <Text variant="h3" weight="bold">{el.symbol}</Text>
            </Card>
          ))}
        </div>
      </Stack>

      {selectedElement && (
        <Modal onClose={() => setSelectedElement(null)} title="Element Details">
          <Stack gap={8}>
            <Text variant="h2">{selectedElement.name} ({selectedElement.symbol})</Text>
            <Text>Atomic Number: {selectedElement.number}</Text>
            <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
            <Text>Category: {selectedElement.category}</Text>
            <Text>Electron Configuration: {selectedElement.electronConfiguration}</Text>
          </Stack>
        </Modal>
      )}
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Row, Text, Button, Badge, Tabs, Icon } from '@ggui-ai/design/primitives';

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Props {
  productId: string;
  title: string;
  price: number;
  currency: string;
  rating: number; // 1-5
  stock: number; // 0+
  description: string;
  specs: Record<string, string>;
  reviews: Review[];
  onAddToCart: (data: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  productId = 'prod-123',
  title = 'Premium Wireless Headphones',
  price = 199.99,
  currency = '$',
  rating = 4,
  stock = 10,
  description = 'Experience crystal clear sound with our premium wireless headphones. Featuring active noise cancellation, 40-hour battery life, and plush memory foam earcups.',
  specs = { 'Weight': '250g', 'Bluetooth': '5.2', 'Battery': '40 hours' },
  reviews = [{ author: 'Alex J.', rating: 5, text: 'Amazing sound quality!', date: '2023-10-01' }],
  onAddToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);

  const handleIncrement = () => {
    if (quantity < stock) setQuantity(prev => prev + 1);
  };

  const handleDecrement = () => {
    if (quantity > 1) setQuantity(prev => prev - 1);
  };

  const stars = Array.from({ length: 5 }, (_, i) => (
    <Icon key={i} name={i < rating ? 'star' : 'star-outline'} size={16} />
  ));

  const specsList = Object.entries(specs).map(([key, value]) => (
    <Row key={key} justify="between">
      <Text variant="label" color="var(--ggui-color-neutral-500)">{key}</Text>
      <Text>{value}</Text>
    </Row>
  ));

  return (
    <Container maxWidth="lg" padding={0}>
      <Stack direction="vertical" gap={32}>
        <Stack direction="horizontal" gap={32} style={{ flexWrap: 'wrap' }}>
          <div style={{
            width: '100%',
            maxWidth: 400,
            height: 300,
            backgroundColor: 'var(--ggui-color-primary-100)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: 'var(--ggui-color-primary-800)',
            fontSize: 'var(--ggui-font-size-xl)',
            fontWeight: 'bold'
          }}>
            {title}
          </div>
          <Stack gap={16} style={{ flex: 1 }}>
            <Text variant="h1">{title}</Text>
            <Text variant="h3" color="var(--ggui-color-primary-600)">{currency}{price.toFixed(2)}</Text>
            <Row gap={4}>{stars}</Row>
            <Badge variant={stock > 5 ? 'success' : 'warning'}>
              {stock > 0 ? (stock > 5 ? 'In Stock' : 'Low Stock') : 'Out of Stock'}
            </Badge>
          </Stack>
        </Stack>

        <Tabs items={[
          { key: 'desc', label: 'Description', content: <Text>{description}</Text> },
          { key: 'specs', label: 'Specifications', content: <Stack gap={8}>{specsList}</Stack> },
          { key: 'reviews', label: 'Reviews', content: <Stack gap={16}>{reviews.map((r, i) => (
            <Card key={i}><Text weight="semibold">{r.author} ({r.rating}★)</Text><Text>{r.text}</Text></Card>
          ))}</Stack> },
        ]} />

        <Row gap={16} align="center">
          <Row align="center" gap={8} style={{ border: '1px solid var(--ggui-color-neutral-300)', padding: '4px', borderRadius: 'var(--ggui-shape-radius-md)' }}>
            <Button onClick={handleDecrement} disabled={quantity <= 1}><Icon name="minus" /></Button>
            <Text style={{ minWidth: 40, textAlign: 'center' }}>{quantity}</Text>
            <Button onClick={handleIncrement} disabled={quantity >= stock}><Icon name="plus" /></Button>
          </Row>
          <Button 
            variant="primary" 
            disabled={stock === 0} 
            onClick={() => onAddToCart?.({ productId, quantity })}
          >
            {stock === 0 ? 'Out of Stock' : 'Add to Cart'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Input, Button, Row, Box } from '@ggui-ai/design/primitives';
import { MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender: string;
  text: string;
  timestamp: string;
  id: string;
}

interface Props {
  title?: string;
  participantCount?: number;
  currentUserId?: string;
  onSend?: (data: { text: string; timestamp: string }) => void;
  // We use this internal hook provided by ggui to safely listen to events
  agentDataHandler?: (callback: (data: any) => void) => void;
}

export default function GeneratedComponent({
  title = "Project Chat",
  participantCount = 3,
  currentUserId = "user-1",
  onSend,
  agentDataHandler,
}: Props) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [typingUsers, setTypingUsers] = useState<string[]>([]);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    if (agentDataHandler) {
      agentDataHandler((data: any) => {
        if (data.type === 'message') {
          setMessages((prev) => [...prev, { ...data, id: Date.now().toString() }]);
          setTypingUsers((prev) => prev.filter((u) => u !== data.sender));
        } else if (data.type === 'typing') {
          if (!typingUsers.includes(data.sender)) {
            setTypingUsers((prev) => [...prev, data.sender]);
          }
        }
      });
    }
  }, [typingUsers, agentDataHandler]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typingUsers]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const timestamp = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    onSend?.({ text: inputValue, timestamp });
    setInputValue('');
  };

  return (
    <Card padding={0} border style={{ height: '500px', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <MotionKeyframes />
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
        <Text variant="h3" weight="semibold">{title}</Text>
        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{participantCount} participants</Text>
      </Box>

      <Stack ref={scrollRef as any} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', gap: 'var(--ggui-spacing-2, 8px)' }}>
        {messages.map((msg, i) => {
          const isMe = msg.sender === currentUserId;
          return (
            <Stack key={msg.id} align={isMe ? 'end' : 'start'} style={{ 
              animation: motionEnabled ? animation.fadeIn : 'none',
              animationDelay: (i * 50) + 'ms'
            }}>
              <Box style={{
                padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                backgroundColor: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-100, #f3f4f6)',
                color: isMe ? 'white' : 'var(--ggui-color-neutral-900, #111827)',
                maxWidth: '80%'
              }}>
                <Text variant="bodySmall" weight="semibold">{isMe ? 'You' : msg.sender}</Text>
                <Text>{msg.text}</Text>
                <Text variant="caption" style={{ opacity: 0.7, fontSize: '10px' }}>{msg.timestamp}</Text>
              </Box>
            </Stack>
          );
        })}
        {typingUsers.map(user => (
          <Text key={user} variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{user} is typing...</Text>
        ))}
      </Stack>

      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
        <Row gap={8}>
          <Input 
            label="Message"
            value={inputValue} 
            onChange={setInputValue} 
            placeholder="Type a message..." 
            style={{ flex: 1 }}
          />
          <Button variant="primary" onClick={handleSend} disabled={!inputValue.trim()}>Send</Button>
        </Row>
      </Box>
    </Card>
  );
}
